APP_ICON_BASE64 = """"""


def carregar_icone_app():
    try:
        from PIL import Image
        return Image.open(io.BytesIO(base64.b64decode(APP_ICON_BASE64))).convert("RGBA")
    except Exception:
        return "🚘"


APP_ICON = carregar_icone_app()

