# ======================================================
# FUNÇÕES AUXILIARES
# ======================================================
def normalizar_texto(valor):
    if pd.isna(valor):
        return ""
    texto = str(valor).upper().strip()
    texto = unicodedata.normalize("NFKD", texto)
    texto = "".join(c for c in texto if not unicodedata.combining(c))
    texto = re.sub(r"\s+", " ", texto)
    return texto



def normalizar_nome_coluna(valor):
    texto = normalizar_texto(valor)
    texto = texto.replace(".", "")
    texto = re.sub(r"[^A-Z0-9 ]", "", texto)
    texto = re.sub(r"\s+", " ", texto).strip()
    return texto



def encontrar_coluna(df, candidatos, obrigatoria=False):
    mapa = {normalizar_nome_coluna(col): col for col in df.columns}
    for candidato in candidatos:
        chave = normalizar_nome_coluna(candidato)
        if chave in mapa:
            return mapa[chave]

    if obrigatoria:
        raise KeyError(
            f"Nenhuma das colunas {candidatos} foi encontrada. "
            f"Colunas disponíveis no arquivo: {list(df.columns)}"
        )
    return None



def converter_numero(serie):
    s = serie.astype(str).str.strip()
    s = s.replace({"": np.nan, "nan": np.nan, "None": np.nan})

    milhar_com_ponto = s.str.match(r"^\d{1,3}(\.\d{3})+$", na=False)
    tem_virgula = s.str.contains(",", na=False)

    s_tratada = s.copy()
    s_tratada.loc[milhar_com_ponto] = s_tratada.loc[milhar_com_ponto].str.replace(".", "", regex=False)
    s_tratada.loc[tem_virgula] = (
        s_tratada.loc[tem_virgula]
        .str.replace(".", "", regex=False)
        .str.replace(",", ".", regex=False)
    )

    s_tratada = s_tratada.str.replace(r"[^0-9.\-]", "", regex=True)
    return pd.to_numeric(s_tratada, errors="coerce")



def converter_data(serie):
    numerico = pd.to_numeric(serie, errors="coerce")
    serial_plausivel = numerico.between(20000, 60000)
    datas_excel = pd.Series(pd.NaT, index=serie.index, dtype="datetime64[ns]")
    datas_excel.loc[serial_plausivel] = (
        pd.to_datetime("1899-12-30") + pd.to_timedelta(numerico.loc[serial_plausivel], unit="D")
    )
    texto = serie.astype(str).str.strip()
    texto = texto.replace({"": np.nan, "nan": np.nan, "None": np.nan, "NaT": np.nan})
    iso_like = texto.str.match(r"^\d{4}[-/]\d{1,2}[-/]\d{1,2}(?:[ T].*)?$", na=False)
    datas_iso = pd.to_datetime(
        texto.where(iso_like),
        errors="coerce",
        format="ISO8601",
    )
    datas_br = pd.to_datetime(
        texto.where(~iso_like),
        errors="coerce",
        dayfirst=True,
    )
    datas_texto = datas_iso.fillna(datas_br)
    return datas_texto.where(~serial_plausivel, datas_excel)



def extrair_ano_modelo_valor(valor):
    """
    Extrai ano modelo de formatos comuns como 2024, 2023/2024, 23/24 ou texto com ano.
    Quando houver dois anos, usa o maior, que normalmente representa o ano modelo.
    """
    if pd.isna(valor):
        return np.nan
    texto = str(valor).strip()
    if not texto or texto.lower() in ["nan", "none", "nat"]:
        return np.nan

    anos_4 = re.findall(r"(?:19|20)\d{2}", texto)
    if anos_4:
        anos = [int(a) for a in anos_4]
        return max(anos)

    anos_2 = re.findall(r"\d{2}", texto)
    if anos_2:
        anos = [2000 + int(a) for a in anos_2]
        anos = [a for a in anos if 2000 <= a <= 2099]
        if anos:
            return max(anos)

    numero = pd.to_numeric(texto, errors="coerce")
    if pd.notna(numero):
        numero = int(numero)
        if 1900 <= numero <= 2099:
            return numero
        if 0 <= numero <= 99:
            return 2000 + numero
    return np.nan



def extrair_ano_modelo(serie):
    return serie.apply(extrair_ano_modelo_valor)



def primeiro_valido(serie):
    valores = serie.dropna()
    return np.nan if valores.empty else valores.iloc[0]



def ultimo_valido(serie):
    valores = serie.dropna()
    return np.nan if valores.empty else valores.iloc[-1]



def juntar_textos(serie):
    valores = serie.dropna().astype(str).str.strip()
    valores = valores[valores != ""]
    if valores.empty:
        return ""
    unicos = pd.Series(valores.unique()).head(30).tolist()
    return " | ".join(unicos)



def formatar_data(valor):
    data = pd.to_datetime(valor, errors="coerce")
    if pd.isna(data):
        return ""
    return data.strftime("%d/%m/%Y")


