def carregar_historico():
    garantir_arquivo_historico()
    try:
        hist = pd.read_csv(ARQUIVO_HISTORICO, sep=";", encoding="utf-8-sig", low_memory=False)
    except Exception:
        hist = pd.read_csv(ARQUIVO_HISTORICO, sep=";", encoding="latin-1", low_memory=False)

    if hist.empty:
        return hist

    if "DATA_PROSPECCAO" in hist.columns:
        hist["DATA_PROSPECCAO"] = converter_data(hist["DATA_PROSPECCAO"])
    if "DATA_VENDA" in hist.columns:
        hist["DATA_VENDA"] = converter_data(hist["DATA_VENDA"])
    if "REVISAO_NUMERO" in hist.columns:
        hist["REVISAO_NUMERO"] = pd.to_numeric(hist["REVISAO_NUMERO"], errors="coerce")
    return hist


def adicionar_ultimo_acionamento(df_base, historico):
    df_saida = df_base.copy()
    df_saida["DATA_ULTIMO_ACIONAMENTO"] = pd.NaT

    if df_saida.empty or historico is None or historico.empty:
        return df_saida
    if "CHASSI" not in df_saida.columns or "CHASSI" not in historico.columns or "DATA_PROSPECCAO" not in historico.columns:
        return df_saida

    hist_chassi = historico[["CHASSI", "DATA_PROSPECCAO"]].copy()
    hist_chassi["CHASSI_NORM"] = hist_chassi["CHASSI"].fillna("").astype(str).apply(normalizar_texto)
    hist_chassi["DATA_PROSPECCAO"] = pd.to_datetime(hist_chassi["DATA_PROSPECCAO"], errors="coerce")
    hist_chassi = hist_chassi[(hist_chassi["CHASSI_NORM"] != "") & hist_chassi["DATA_PROSPECCAO"].notna()].copy()

    if hist_chassi.empty:
        return df_saida

    ultimo = (
        hist_chassi.groupby("CHASSI_NORM", as_index=False)["DATA_PROSPECCAO"]
        .max()
        .rename(columns={"DATA_PROSPECCAO": "DATA_ULTIMO_ACIONAMENTO"})
    )

    df_saida["CHASSI_NORM"] = df_saida["CHASSI"].fillna("").astype(str).apply(normalizar_texto)
    df_saida = df_saida.drop(columns=["DATA_ULTIMO_ACIONAMENTO"]).merge(ultimo, on="CHASSI_NORM", how="left")
    df_saida = df_saida.drop(columns=["CHASSI_NORM"])
    return df_saida



# ======================================================
# AGENDAMENTOS FUTUROS
# ======================================================
def garantir_arquivo_agendamentos_futuros():
    """
    Cria o arquivo simples de agendamentos futuros caso ainda não exista.

    Uso diário:
    - preencher a coluna CHASSI com os veículos já agendados;
    - clicar em Atualizar base no painel.
    """
    if not ARQUIVO_AGENDAMENTOS_FUTUROS.exists() and not ARQUIVO_AGENDAMENTOS_FUTUROS_EXCEL.exists():
        pd.DataFrame(columns=["CHASSI"]).to_csv(
            ARQUIVO_AGENDAMENTOS_FUTUROS,
            index=False,
            sep=";",
            encoding="utf-8-sig",
        )


def carregar_chassis_agendados():
    """
    Lê os chassis já agendados.
    Aceita:
    - agendamentos_futuros.csv
    - agendamentos_futuros.xlsx

    A coluna obrigatória é CHASSI.
    """
    garantir_arquivo_agendamentos_futuros()

    try:
        if ARQUIVO_AGENDAMENTOS_FUTUROS_EXCEL.exists():
            df_ag = pd.read_excel(ARQUIVO_AGENDAMENTOS_FUTUROS_EXCEL, dtype=str)
        elif ARQUIVO_AGENDAMENTOS_FUTUROS.exists():
            try:
                df_ag = pd.read_csv(ARQUIVO_AGENDAMENTOS_FUTUROS, sep=";", encoding="utf-8-sig", dtype=str)
            except Exception:
                df_ag = pd.read_csv(ARQUIVO_AGENDAMENTOS_FUTUROS, sep=",", encoding="utf-8-sig", dtype=str)
        else:
            return set()

        if df_ag.empty:
            return set()

        df_ag.columns = df_ag.columns.astype(str).str.strip()
        col_chassi = encontrar_coluna(df_ag, CANDIDATOS_COLUNA_CHASSI)
        if not col_chassi:
            return set()

        chassis = (
            df_ag[col_chassi]
            .dropna()
            .astype(str)
            .str.strip()
            .apply(normalizar_texto)
        )
        chassis = chassis[chassis != ""]
        chassis = chassis[chassis.str.lower() != "nan"]
        return set(chassis.tolist())
    except Exception:
        return set()


def aplicar_status_agendado(resultado):
    """
    Marca como AGENDADO os chassis que constam em agendamentos_futuros.csv/xlsx.

    Não altera:
    - REVISADO, porque já fez a revisão;
    - OUTROS SERVIÇOS, porque não está na régua de revisão;
    - VEÍCULO VENDIDO, se futuramente esse status estiver na base.
    """
    if resultado is None or resultado.empty or "CHASSI" not in resultado.columns:
        return resultado

    chassis_agendados = carregar_chassis_agendados()
    if not chassis_agendados:
        return resultado

    if "STATUS_PROSPECCAO" not in resultado.columns:
        return resultado

    status_protegidos = ["REVISADO", "OUTROS SERVIÇOS", "VEÍCULO VENDIDO", "VEICULO VENDIDO"]
    mask_agendado = (
        resultado["CHASSI"].fillna("").astype(str).apply(normalizar_texto).isin(chassis_agendados)
        & ~resultado["STATUS_PROSPECCAO"].fillna("").astype(str).isin(status_protegidos)
    )

    resultado.loc[mask_agendado, "STATUS_PROSPECCAO"] = "AGENDADO"
    resultado.loc[mask_agendado, "MOTIVO_STATUS"] = (
        "Chassi consta no arquivo agendamentos_futuros.csv/xlsx; evitar novo contato de prospecção."
    )
    return resultado



def montar_linha_historico(row, data_prospeccao, resultado, observacao):
    return {
        "DATA_PROSPECCAO": pd.to_datetime(data_prospeccao),
        "CHASSI": row.get("CHASSI", ""),
        "PLACA": row.get("PLACA", ""),
        "NOME_CLIENTE": row.get("NOME_DO_CLIENTE", ""),
        "CPF_CNPJ": row.get("CPF_CNPJ", ""),
        "CELULAR": row.get("CELULAR", ""),
        "TELEFONE": row.get("TELEFONE", ""),
        "FAX": row.get("FAX", ""),
        "DATA_VENDA": row.get("DATA_VENDA", pd.NaT),
        "CONCESSIONARIA": row.get("NOME_CONCESSIONARIA", ""),
        "MARCA": row.get("VEICULO_MARCA", ""),
        "STATUS_REVISAO": row.get("STATUS_PROSPECCAO", ""),
        "REVISAO_NUMERO": row.get("QUAL_REVISAO", np.nan),
        "RESULTADO_CONTATO": resultado,
        "OBSERVACAO": observacao,
    }


def registrar_prospeccao(row, data_prospeccao, resultado, observacao):
    garantir_arquivo_historico()
    hist = carregar_historico()
    novo = pd.DataFrame([montar_linha_historico(row, data_prospeccao, resultado, observacao)])
    hist = pd.concat([hist, novo], ignore_index=True)
    hist.to_csv(ARQUIVO_HISTORICO, index=False, sep=";", encoding="utf-8-sig")


def registrar_prospeccao_massa(df_base, data_prospeccao, resultado, observacao):
    garantir_arquivo_historico()
    hist = carregar_historico()

    if df_base.empty:
        return 0

    linhas = [
        montar_linha_historico(row, data_prospeccao, resultado, observacao)
        for row in df_base.to_dict(orient="records")
    ]
    novo = pd.DataFrame(linhas)
    hist = pd.concat([hist, novo], ignore_index=True)
    hist.to_csv(ARQUIVO_HISTORICO, index=False, sep=";", encoding="utf-8-sig")
    return len(novo)


# ======================================================
# REGRAS DE CLASSIFICAÇÃO
# ======================================================
def identificar_revisao(texto_normalizado):
    """
    Identifica revisão usando o texto combinado das colunas SERVIÇOS + DESCRIÇÃO.

    Regra importante:
    - A base pode trazer "SERVIÇOS GERAIS" na coluna X e "revisão 10.000" na coluna Y.
    - Por isso, a identificação precisa olhar o conteúdo completo e não apenas uma coluna.
    - A busca considera variações como REVISAO, REVISÃO, REV, REV., REV 10.000,
      REVISAO 30.000 KM, REV GRATUITA, troca de óleo e manutenção programada.
    """
    if not texto_normalizado:
        return False

    texto = texto_normalizado

    padroes = [
        # Revisão escrita por extenso ou variações iniciadas por REVIS...
        r"\bREVIS[A-Z]*\b",

        # Abreviações: REV, REV., REV 10.000, REV. 10000, REV GRATUITA
        r"\bREV\s*\.?\s*(?:[0-9]|DE\b|GRATUITA\b|PERIODICA\b|PROGRAMADA\b|PLANO\b|KM\b|$|\s)",

        # Padrões de revisão por km/tempo mesmo quando não aparece a palavra KM
        r"\b(?:REVISAO|REV\.?|REVIS[A-Z]*)\s*(?:DE\s*)?[0-9]{1,3}(?:\.[0-9]{3})+\s*(?:KM)?\b",
        r"\b(?:REVISAO|REV\.?|REVIS[A-Z]*)\s*(?:DE\s*)?[0-9]{4,6}\s*(?:KM)?\b",
        r"\b[0-9]{1,3}(?:\.[0-9]{3})+\s*(?:KM)?\s*OU\s*[0-9]{1,2}\s*MESES\b",

        # Manutenção/revisão programada
        r"MANUTENCAO\s+PROGRAMADA",
        r"REVISAO\s+PERIODICA",
        r"REVISAO\s+PROGRAMADA",
        r"PLANO\s+DE\s+REVISAO",

        # Entrega
        r"REVISAO\s+DE\s+ENTREGA",
        r"ENTREGA\s+TECNICA",

        # Óleo/filtro como manutenção de revisão
        r"TROCA\s+DE\s+OLEO",
        r"SUB\.?\s*OLEO",
        r"SUBSTITUICAO\s+DE\s+OLEO",
        r"OLEO\s+MOTOR",
        r"FILTRO\s+DE\s+OLEO",
    ]

    return any(re.search(p, texto) for p in padroes)



def identificar_revisao_entrega(tipo_os_normalizado, texto_servico_normalizado):
    tipo = tipo_os_normalizado or ""
    texto = texto_servico_normalizado or ""
    eh_tipo_r1 = bool(re.search(r"\bR\s*1\b|\bR1\b", tipo))
    tem_entrega = any(p in texto for p in ["ENTREGA", "REVISAO DE ENTREGA", "ENTREGA TECNICA"])
    return (eh_tipo_r1 and tem_entrega) or ("REVISAO DE ENTREGA" in texto) or ("ENTREGA TECNICA" in texto)



def inferir_motorizacao(marca, modelo):
    marca_n = normalizar_texto(marca)
    modelo_n = normalizar_texto(modelo)
    texto = f"{marca_n} {modelo_n}"

    pistas_diesel = ["DIESEL", "MULTIJET", "TDI", "JTD", "TURBO D"]
    if any(p in texto for p in pistas_diesel):
        return "DIESEL"

    modelos_diesel = {
        "PEUGEOT": ["EXPERT"],
        "CITROEN": ["JUMPY"],
        "FIAT": ["TITANO", "SCUDO", "DUCATO"],
        "RAM": ["2500", "3500"],
        "JEEP": ["GLADIATOR"],
    }
    modelos_gasolina = {
        "RAM": ["1500"],
        "JEEP": ["WRANGLER"],
    }

    for marca_base, modelos in modelos_diesel.items():
        if marca_n == normalizar_texto(marca_base):
            if any(normalizar_texto(m) in modelo_n for m in modelos):
                return "DIESEL"

    for marca_base, modelos in modelos_gasolina.items():
        if marca_n == normalizar_texto(marca_base):
            if any(normalizar_texto(m) in modelo_n for m in modelos):
                return "GASOLINA"

    return "FLEX"



def regra_km(marca, motorizacao):
    marca_n = normalizar_texto(marca)
    if motorizacao == "DIESEL":
        return pd.Series({"KM_MIN": 19000, "KM_MAX": 20999, "KM_IDEAL": 20000})
    if marca_n in ["JEEP", "RAM"]:
        return pd.Series({"KM_MIN": 11000, "KM_MAX": 12999, "KM_IDEAL": 12000})
    return pd.Series({"KM_MIN": 9000, "KM_MAX": 10999, "KM_IDEAL": 10000})



def classificar_status(row):
    if row.get("SEM_REVISAO_IDENTIFICADA", False):
        return "OUTROS SERVIÇOS"

    data_base = row.get("DATA_BASE_PROJECAO")
    if pd.isna(data_base):
        return "SEM HISTÓRICO SUFICIENTE"

    sem_media = pd.isna(row.get("MEDIA_KM_DIA")) or row.get("MEDIA_KM_DIA", 0) <= 0
    km_desde = row.get("KM_DESDE_ULTIMA_REVISAO_EST", 0)
    if pd.isna(km_desde):
        km_desde = 0

    dentro_km = (not sem_media) and (row["KM_MIN"] <= km_desde <= row["KM_MAX"])
    dentro_tempo = row["DATA_MIN_TEMPO"] <= HOJE <= row["DATA_MAX_TEMPO"]
    vencido_km = (not sem_media) and (km_desde > row["KM_MAX"])
    vencido_tempo = HOJE > row["DATA_MAX_TEMPO"]

    if vencido_km or vencido_tempo:
        perda_por_km = (not sem_media) and (km_desde > (row["KM_MAX"] + 5000))
        perda_por_tempo = HOJE > row["DATA_LIMITE_REVALIDACAO_TEMPO"]
        if perda_por_km and perda_por_tempo:
            return "PERDA DE GARANTIA"
        return "POSSÍVEL REVALIDAÇÃO"

    if dentro_km or dentro_tempo:
        return "CONTATAR AGORA"

    if HOJE >= row["DATA_ATUALIZAR_KM"]:
        return "ATUALIZAR KM"

    return "AGUARDANDO"



def diagnosticar_motivo(row):
    status = row.get("STATUS_PROSPECCAO", "")

    if status == "REVISADO":
        data_rev = row.get("DATA_REVISAO_RELATORIO", pd.NaT)
        if pd.isna(pd.to_datetime(data_rev, errors="coerce")):
            data_rev = row.get("DATA_ULTIMA_REVISAO", pd.NaT)
        revisao_numero = row.get("QUAL_REVISAO", "")
        data_txt = formatar_data(data_rev)
        if data_txt:
            return f"Revisão {revisao_numero} já realizada em {data_txt}."
        return f"Revisão {revisao_numero} já realizada."

    if status == "AGENDADO":
        return "Cliente já consta na base de agendamentos futuros; não precisa ser acionado novamente para esta revisão."

    if status == "OUTROS SERVIÇOS":
        return (
            "Não foi encontrada nenhuma passagem classificada como revisão, troca de óleo, "
            "manutenção programada ou R1/revisão de entrega."
        )

    if row.get("ORIGEM_BASE_PROJECAO", "") == "BASE DE VENDAS DO PERÍODO":
        data_venda_txt = formatar_data(row.get("DATA_VENDA", pd.NaT))
        data_contato_txt = formatar_data(row.get("DATA_SUGERIDA_CONTATO", pd.NaT))
        if data_venda_txt and data_contato_txt:
            return f"1ª revisão projetada pela base de veículos vendidos: venda em {data_venda_txt}; contato sugerido a partir de {data_contato_txt}."
        if data_venda_txt:
            return f"1ª revisão projetada pela base de veículos vendidos: venda em {data_venda_txt}."
        return "1ª revisão projetada pela base de veículos vendidos."

    if status == "SEM HISTÓRICO SUFICIENTE":
        motivos = []
        if pd.isna(row.get("DATA_BASE_PROJECAO")):
            motivos.append("sem data base para projeção")
        if pd.isna(row.get("DATA_VENDA")):
            motivos.append("DATA VENDA vazia/inválida")
        if pd.isna(row.get("DATA_ULTIMA_REVISAO")):
            motivos.append("DATA DA REVISÃO vazia/inválida")
        if not motivos:
            motivos.append("faltam dados mínimos para projetar")
        return " | ".join(motivos)

    if pd.isna(row.get("MEDIA_KM_DIA")) or row.get("MEDIA_KM_DIA", 0) <= 0:
        return "Sem média confiável de KM/dia; classificação feita pela régua de tempo."

    return "OK"



def classificar_faixa_retorno(meses):
    if pd.isna(meses):
        return "Sem faixa"
    if meses <= 6:
        return "Até 6 meses"
    if meses <= 9:
        return "7 a 9 meses"
    if meses <= 12:
        return "10 a 12 meses"
    return "13+ meses"


def extrair_km_revisao(texto):
    """
    Lê o KM informado no texto da revisão, usando SERVIÇOS + DESCRIÇÃO.

    Exemplos aceitos:
    - Revisão de 10.000km ou 12 meses
    - Revisão 10.000
    - REV. 10000
    - REVISAO 30.000 KM PLANO
    - SERVIÇOS GERAIS revisão 10.000
    """
    texto_n = normalizar_texto(texto)
    if not texto_n:
        return np.nan

    padroes = [
        r"(?:REVISAO|REV\.?|REVIS[A-Z]*)\s*(?:DE\s*)?([0-9]{1,3}(?:\.[0-9]{3})+|[0-9]{4,6})\s*(?:KM)?\b",
        r"([0-9]{1,3}(?:\.[0-9]{3})+|[0-9]{4,6})\s*KM\s*OU\s*[0-9]{1,2}\s*MESES",
        r"([0-9]{1,3}(?:\.[0-9]{3})+|[0-9]{4,6})\s*(?:KM)?\s*PLANO",
    ]

    for padrao in padroes:
        m = re.search(padrao, texto_n)
        if m:
            valor = str(m.group(1)).replace(".", "")
            numero = pd.to_numeric(valor, errors="coerce")
            if pd.notna(numero) and 1000 <= numero <= 300000:
                return numero
    return np.nan


def calcular_tipo_revisao(row):
    """
    Padroniza o tipo de revisão em poucas opções operacionais:

    POR TEMPO      = já bateu pela régua de tempo, ou a previsão principal é por tempo.
    POR KM         = já bateu pela régua de quilometragem.
    PREVISTO POR KM = ainda não bateu, mas a projeção indica que o KM chegará antes do tempo.
    KM E TEMPO     = já bateu pelos dois critérios.
    OUTROS SERVIÇOS = não é revisão identificada.
    """
    if row.get("SEM_REVISAO_IDENTIFICADA", False):
        return "OUTROS SERVIÇOS"

    data_base = row.get("DATA_BASE_PROJECAO")
    if pd.isna(data_base):
        return "POR TEMPO"

    sem_media = pd.isna(row.get("MEDIA_KM_DIA")) or row.get("MEDIA_KM_DIA", 0) <= 0
    km_desde = row.get("KM_DESDE_ULTIMA_REVISAO_EST", 0)
    if pd.isna(km_desde):
        km_desde = 0

    bateu_tempo = HOJE >= row.get("DATA_MIN_TEMPO")
    bateu_km = (not sem_media) and (km_desde >= row.get("KM_MIN", np.inf))

    if bateu_km and bateu_tempo:
        return "KM E TEMPO"
    if bateu_km:
        return "POR KM"
    if bateu_tempo:
        return "POR TEMPO"

    # Sem média confiável, não dá para prever por KM; fica como tempo.
    if sem_media:
        return "POR TEMPO"

    data_km = row.get("DATA_MIN_KM")
    data_tempo = row.get("DATA_MIN_TEMPO")

    # Se o KM estimado chegar antes da janela de tempo, destacamos como previsão por KM.
    if pd.notna(data_km) and pd.notna(data_tempo) and data_km < data_tempo:
        return "PREVISTO POR KM"

    # Todos os demais cenários previstos ficam resumidos como POR TEMPO.
    return "POR TEMPO"


def classificar_perfil_retorno(meses):
    """
    Classifica o comportamento de retorno do cliente.
    A régua conversa com a regra de garantia:
    - até 9 meses: cliente volta cedo;
    - até 12 meses e 29 dias: dentro do prazo ideal;
    - até 5 meses após o limite: atrasado, mas ainda recuperável;
    - acima disso: alto risco de perda.
    """
    if pd.isna(meses):
        return "SEM PERFIL"

    if meses <= 9:
        return "RETORNA CEDO"
    if meses <= 12.97:
        return "RETORNA NO PRAZO IDEAL"
    if meses <= 17.97:
        return "RETORNA ATRASADO"
    return "ALTO RISCO DE PERDA"


def classificar_tipo_revisao_realizada(row):
    """
    Classifica a revisão já executada como POR TEMPO, POR KM ou KM E TEMPO.

    Usa:
    - meses entre a base anterior e a revisão atual;
    - KM da revisão descrito no serviço, quando existir;
    - KM real da passagem.

    Se o cliente voltou antes de 11 meses e a revisão foi identificada, a tendência operacional é
    considerar que voltou por KM, mesmo quando a descrição de KM não veio perfeita.
    """
    meses = row.get("MESES_RETORNO")
    km_atual = row.get("KM")
    km_revisao_texto = row.get("KM_REVISAO_TEXTO")
    km_ideal = row.get("KM_IDEAL")
    revisao_numero = row.get("REVISAO_NUMERO")

    km_referencia = km_revisao_texto
    if pd.isna(km_referencia) or km_referencia <= 0:
        if pd.notna(km_ideal) and pd.notna(revisao_numero):
            km_referencia = km_ideal * revisao_numero

    km_minimo = np.nan
    if pd.notna(km_referencia) and km_referencia > 0:
        km_minimo = max(km_referencia - 1000, 0)

    bateu_km = pd.notna(km_atual) and pd.notna(km_minimo) and km_atual >= km_minimo
    bateu_tempo = pd.notna(meses) and meses >= 11

    if bateu_km and bateu_tempo:
        return "KM E TEMPO"
    if bateu_km:
        return "POR KM"
    if bateu_tempo:
        return "POR TEMPO"

    if pd.notna(meses) and meses < 11:
        return "POR KM"

    return "POR TEMPO"



def montar_linhas_revisoes_realizadas_para_relatorio(eventos_analiticos):
    """
    Cria linhas de revisões já realizadas para a mesma régua dos filtros da Aba 1.

    Antes, a Aba 1 mostrava apenas a PRÓXIMA revisão a prospectar.
    Com isso, quando o cliente já tinha feito a 1ª revisão, ele saía do filtro
    "REVISÃO NÚMERO = 1" e passava para "REVISÃO NÚMERO = 2".

    Agora, cada revisão efetivamente realizada também entra no relatório da sua
    competência:
    - QUAL_REVISAO = revisão que foi realizada;
    - DATA_SUGERIDA_CONTATO = data prevista da revisão pela régua de tempo;
    - STATUS_PROSPECCAO = REVISADO.
    """
    if eventos_analiticos is None or eventos_analiticos.empty:
        return pd.DataFrame()

    linhas = eventos_analiticos.copy()

    if "DATA_EXECUCAO_SERVICO" in linhas.columns:
        linhas = linhas.rename(columns={"DATA_EXECUCAO_SERVICO": "DATA_ULTIMA_REVISAO"})
    elif "DATA_REFERENCIA" in linhas.columns:
        linhas = linhas.rename(columns={"DATA_REFERENCIA": "DATA_ULTIMA_REVISAO"})

    if "KM" in linhas.columns and "KM_ULTIMA_REVISAO" not in linhas.columns:
        linhas = linhas.rename(columns={"KM": "KM_ULTIMA_REVISAO"})

    linhas["SEM_REVISAO_IDENTIFICADA"] = False
    linhas["STATUS_PROSPECCAO"] = "REVISADO"
    linhas["STATUS_HISTORICO_REVISAO"] = "REVISADO"
    linhas["QUAL_REVISAO"] = pd.to_numeric(linhas.get("REVISAO_NUMERO", np.nan), errors="coerce")
    linhas["TIPO_REVISAO"] = linhas.get("TIPO_REVISAO_REALIZADA", "REVISADO")
    linhas["DATA_BASE_PROJECAO"] = pd.to_datetime(linhas.get("BASE_DATA_ANALITICA", pd.NaT), errors="coerce")

    # Para a competência do relatório, usamos a janela de tempo:
    # revisão 1 = DATA VENDA + 11 meses; demais = revisão anterior + 11 meses.
    linhas["DATA_MIN_TEMPO"] = linhas["DATA_BASE_PROJECAO"] + pd.DateOffset(months=11)
    linhas["DATA_MAX_TEMPO"] = linhas["DATA_BASE_PROJECAO"] + pd.DateOffset(months=12, days=29)
    linhas["DATA_SUGERIDA_CONTATO"] = linhas["DATA_MIN_TEMPO"]
    linhas["ANO_PROX"] = linhas["DATA_SUGERIDA_CONTATO"].dt.year.astype("Int64").astype(str)
    linhas["MES_PROX"] = linhas["DATA_SUGERIDA_CONTATO"].dt.month
    linhas["DATA_REVISAO_RELATORIO"] = pd.to_datetime(linhas["DATA_ULTIMA_REVISAO"], errors="coerce")
    linhas["ORIGEM_RELATORIO"] = "REVISÃO REALIZADA"
    linhas["ORIGEM_BASE_PROJECAO"] = "HISTÓRICO DE REVISÃO REALIZADA"

    return linhas


def montar_resumo_tempo(df_base, coluna_grupo):
    """
    Monta tabela padrão de tempo médio para revisão, marca, concessionária,
    modelo ou tipo de revisão.
    """
    if df_base.empty or coluna_grupo not in df_base.columns:
        return pd.DataFrame()

    resumo = (
        df_base.groupby(coluna_grupo, dropna=False)
        .agg(
            QUANTIDADE=(coluna_grupo, "size"),
            TEMPO_MEDIO_MESES=("MESES_RETORNO", "mean"),
            MEDIANA_MESES=("MESES_RETORNO", "median"),
        )
        .reset_index()
    )

    total = resumo["QUANTIDADE"].sum()
    resumo["% DO TOTAL"] = np.where(total > 0, (resumo["QUANTIDADE"] / total) * 100, 0)
    resumo = resumo.sort_values(["QUANTIDADE", "TEMPO_MEDIO_MESES"], ascending=[False, True])
    return resumo



