def limpar_telefone(valor):
    if pd.isna(valor):
        return ""
    texto = str(valor)
    texto = re.sub(r"\D", "", texto)
    return texto


def calcular_plano_acao_campanha(row):
    status = str(row.get("STATUS_ATUAL", "")).upper().strip()
    prox = pd.to_datetime(row.get("DATA_PROXIMO_CONTATO"), errors="coerce")

    if status == "NÃO ACIONADO":
        return "Realizar primeiro contato"
    if status == "ACIONADO":
        return "Acompanhar retorno / fazer follow-up"
    if status == "SEM INTERAÇÃO":
        return "Recontatar cliente"
    if status == "RECONTATO FUTURO":
        if pd.notna(prox) and prox.date() <= HOJE.date():
            return "Recontato vencido: acionar hoje"
        return "Aguardar data de recontato"
    if status == "OPORTUNIDADE PERDIDA":
        return "Analisar motivo da perda"
    if status == "CONVERTIDO":
        return "Finalizado"
    return "Classificar status"


def calcular_prioridade_campanha(row):
    status = str(row.get("STATUS_ATUAL", "")).upper().strip()
    prox = pd.to_datetime(row.get("DATA_PROXIMO_CONTATO"), errors="coerce")
    tentativas = pd.to_numeric(row.get("QTD_TENTATIVAS", 0), errors="coerce")
    if pd.isna(tentativas):
        tentativas = 0

    if status == "CONVERTIDO":
        return "FINALIZADO"
    if status == "OPORTUNIDADE PERDIDA":
        return "ANÁLISE"
    if status == "NÃO ACIONADO":
        return "ALTA"
    if status == "RECONTATO FUTURO" and pd.notna(prox) and prox.date() <= HOJE.date():
        return "ALTA"
    if status == "SEM INTERAÇÃO" and tentativas >= 3:
        return "BAIXA"
    if status in ["SEM INTERAÇÃO", "ACIONADO", "RECONTATO FUTURO"]:
        return "MÉDIA"
    return "MÉDIA"


def ler_arquivo_importado(uploaded_file):
    nome = uploaded_file.name.lower()
    try:
        conteudo = uploaded_file.getvalue()
    except Exception:
        uploaded_file.seek(0)
        conteudo = uploaded_file.read()

    if nome.endswith(".xlsx") or nome.endswith(".xls"):
        return pd.read_excel(io.BytesIO(conteudo), dtype=str)

    # CSV: tenta primeiro ponto e vírgula, depois vírgula.
    for sep in [";", ","]:
        for enc in ["latin-1", "utf-8-sig", "utf-8"]:
            try:
                df_upload = pd.read_csv(io.BytesIO(conteudo), sep=sep, encoding=enc, dtype=str)
                if df_upload.shape[1] > 1:
                    return df_upload
            except Exception:
                pass

    return pd.read_csv(io.BytesIO(conteudo), dtype=str)


def coluna_mapeada(df_origem, nome_coluna):
    if nome_coluna and nome_coluna != "Não importar" and nome_coluna in df_origem.columns:
        return df_origem[nome_coluna]
    return pd.Series([""] * len(df_origem))


def padronizar_base_campanha(df_origem, mapeamento, id_campanha, nome_campanha, origem_base, tipo_campanha):
    df_pad = pd.DataFrame()
    df_pad["ID_CAMPANHA"] = id_campanha
    df_pad["NOME_CAMPANHA"] = nome_campanha
    df_pad["ORIGEM_BASE"] = origem_base
    df_pad["TIPO_CAMPANHA"] = tipo_campanha
    df_pad["DATA_IMPORTACAO"] = HOJE

    df_pad["CHASSI"] = coluna_mapeada(df_origem, mapeamento.get("CHASSI")).astype(str).str.strip()
    df_pad["NOME_CLIENTE"] = coluna_mapeada(df_origem, mapeamento.get("NOME_CLIENTE")).astype(str).str.strip()
    df_pad["CPF_CNPJ"] = coluna_mapeada(df_origem, mapeamento.get("CPF_CNPJ")).astype(str).str.strip()
    df_pad["CELULAR"] = coluna_mapeada(df_origem, mapeamento.get("CELULAR")).apply(limpar_telefone)
    df_pad["TELEFONE"] = coluna_mapeada(df_origem, mapeamento.get("TELEFONE")).apply(limpar_telefone)
    df_pad["FIXO"] = coluna_mapeada(df_origem, mapeamento.get("FIXO")).apply(limpar_telefone)
    df_pad["PLACA"] = coluna_mapeada(df_origem, mapeamento.get("PLACA")).astype(str).str.strip().str.upper()
    df_pad["MARCA"] = coluna_mapeada(df_origem, mapeamento.get("MARCA")).astype(str).str.strip().str.upper()
    df_pad["MODELO"] = coluna_mapeada(df_origem, mapeamento.get("MODELO")).astype(str).str.strip().str.upper()

    df_pad = df_pad.replace({"nan": "", "None": "", "NaT": ""})
    df_pad = df_pad[
        (df_pad["CHASSI"].astype(str).str.strip() != "")
        | (df_pad["NOME_CLIENTE"].astype(str).str.strip() != "")
        | (df_pad["CPF_CNPJ"].astype(str).str.strip() != "")
        | (df_pad["CELULAR"].astype(str).str.strip() != "")
        | (df_pad["TELEFONE"].astype(str).str.strip() != "")
        | (df_pad["FIXO"].astype(str).str.strip() != "")
    ].copy()

    # Remove apenas duplicidades exatas da mesma oportunidade importada.
    # Não remove por CPF sozinho, porque um cliente pode ter mais de um veículo/oportunidade.
    df_pad = df_pad.drop_duplicates(
        subset=["CHASSI", "NOME_CLIENTE", "CPF_CNPJ", "CELULAR", "TELEFONE", "FIXO", "PLACA"],
        keep="first",
    )

    df_pad = df_pad.reset_index(drop=True)
    df_pad["ID_CLIENTE_CAMPANHA"] = [
        f"{id_campanha}_{i+1:06d}" for i in range(len(df_pad))
    ]
    df_pad["STATUS_ATUAL"] = "NÃO ACIONADO"
    df_pad["MOTIVO_PERDA"] = ""
    df_pad["DATA_STATUS_ATUAL"] = HOJE
    df_pad["QTD_TENTATIVAS"] = 0
    df_pad["DATA_PROXIMO_CONTATO"] = pd.NaT
    df_pad["OBSERVACAO_ATUAL"] = "Cliente importado na campanha."
    df_pad["PLANO_ACAO"] = df_pad.apply(calcular_plano_acao_campanha, axis=1)
    df_pad["PRIORIDADE"] = df_pad.apply(calcular_prioridade_campanha, axis=1)

    return df_pad[COLUNAS_CLIENTES_CAMPANHAS]


def importar_campanha(df_pad, id_campanha, nome_campanha, origem_base, tipo_campanha):
    campanhas = carregar_campanhas()
    clientes = carregar_clientes_campanhas()
    hist = carregar_historico_status_campanhas()

    nome_normalizado = normalizar_texto(nome_campanha)
    nomes_existentes = campanhas["NOME_CAMPANHA"].fillna("").apply(normalizar_texto) if "NOME_CAMPANHA" in campanhas.columns else pd.Series(dtype=str)
    if nome_normalizado and nome_normalizado in set(nomes_existentes):
        raise ValueError("Já existe uma campanha com esse nome. Use um nome diferente para evitar duplicidade nos indicadores.")

    if id_campanha in set(campanhas.get("ID_CAMPANHA", pd.Series(dtype=str)).astype(str)):
        raise ValueError("ID de campanha duplicado. Tente importar novamente em alguns segundos.")

    nova_campanha = pd.DataFrame([{
        "ID_CAMPANHA": id_campanha,
        "NOME_CAMPANHA": nome_campanha,
        "ORIGEM_BASE": origem_base,
        "TIPO_CAMPANHA": tipo_campanha,
        "DATA_IMPORTACAO": HOJE,
        "QTD_CLIENTES": len(df_pad),
    }])

    historico_inicial = pd.DataFrame({
        "DATA_MOVIMENTO": HOJE,
        "ID_CLIENTE_CAMPANHA": df_pad["ID_CLIENTE_CAMPANHA"],
        "ID_CAMPANHA": df_pad["ID_CAMPANHA"],
        "NOME_CAMPANHA": df_pad["NOME_CAMPANHA"],
        "CHASSI": df_pad["CHASSI"],
        "NOME_CLIENTE": df_pad["NOME_CLIENTE"],
        "STATUS_ANTERIOR": "",
        "STATUS_NOVO": "NÃO ACIONADO",
        "MOTIVO_PERDA": "",
        "OBSERVACAO": "Importação inicial da campanha.",
        "DATA_PROXIMO_CONTATO": pd.NaT,
    })

    campanhas = pd.concat([campanhas, nova_campanha], ignore_index=True)
    clientes = pd.concat([clientes, df_pad], ignore_index=True)
    hist = pd.concat([hist, historico_inicial], ignore_index=True)

    salvar_campanhas(campanhas)
    salvar_clientes_campanhas(clientes)
    salvar_historico_status_campanhas(hist)


def atualizar_status_campanha(ids_clientes, novo_status, motivo_perda, observacao, data_proximo_contato):
    clientes = carregar_clientes_campanhas()
    hist = carregar_historico_status_campanhas()

    ids_clientes = set(ids_clientes)
    if not ids_clientes:
        return 0

    if novo_status not in STATUS_CAMPANHA:
        raise ValueError("Status de campanha inválido.")

    if novo_status == "OPORTUNIDADE PERDIDA" and not motivo_perda:
        raise ValueError("Informe o motivo da perda para oportunidades perdidas.")

    if novo_status == "RECONTATO FUTURO" and not data_proximo_contato:
        raise ValueError("Informe a data do próximo contato para RECONTATO FUTURO.")

    if novo_status != "OPORTUNIDADE PERDIDA":
        motivo_perda = ""

    mask = clientes["ID_CLIENTE_CAMPANHA"].isin(ids_clientes)
    alterados = clientes[mask].copy()
    if alterados.empty:
        return 0

    linhas_hist = []
    for _, row in alterados.iterrows():
        linhas_hist.append({
            "DATA_MOVIMENTO": HOJE,
            "ID_CLIENTE_CAMPANHA": row.get("ID_CLIENTE_CAMPANHA", ""),
            "ID_CAMPANHA": row.get("ID_CAMPANHA", ""),
            "NOME_CAMPANHA": row.get("NOME_CAMPANHA", ""),
            "CHASSI": row.get("CHASSI", ""),
            "NOME_CLIENTE": row.get("NOME_CLIENTE", ""),
            "STATUS_ANTERIOR": row.get("STATUS_ATUAL", ""),
            "STATUS_NOVO": novo_status,
            "MOTIVO_PERDA": motivo_perda,
            "OBSERVACAO": observacao,
            "DATA_PROXIMO_CONTATO": pd.to_datetime(data_proximo_contato) if data_proximo_contato else pd.NaT,
        })

    clientes.loc[mask, "STATUS_ATUAL"] = novo_status
    clientes.loc[mask, "MOTIVO_PERDA"] = motivo_perda
    clientes.loc[mask, "DATA_STATUS_ATUAL"] = HOJE
    clientes.loc[mask, "DATA_PROXIMO_CONTATO"] = pd.to_datetime(data_proximo_contato) if data_proximo_contato else pd.NaT
    clientes.loc[mask, "OBSERVACAO_ATUAL"] = observacao
    clientes.loc[mask, "QTD_TENTATIVAS"] = (
        pd.to_numeric(clientes.loc[mask, "QTD_TENTATIVAS"], errors="coerce").fillna(0).astype(int) + 1
    )
    clientes["PLANO_ACAO"] = clientes.apply(calcular_plano_acao_campanha, axis=1)
    clientes["PRIORIDADE"] = clientes.apply(calcular_prioridade_campanha, axis=1)

    hist = pd.concat([hist, pd.DataFrame(linhas_hist)], ignore_index=True)

    salvar_clientes_campanhas(clientes)
    salvar_historico_status_campanhas(hist)
    return len(alterados)




