# FUNÇÕES - BASE DE VENDAS / 1ª REVISÃO
# ======================================================
def obter_arquivo_base_vendas_primeira_revisao():
    for arquivo in ARQUIVOS_BASE_VENDAS_PRIMEIRA_REVISAO:
        if arquivo.exists():
            return arquivo
    return None


def salvar_upload_base_vendas_primeira_revisao(uploaded_file):
    """Salva a base mensal de veículos vendidos para uso automático na régua da 1ª revisão."""
    nome = uploaded_file.name.lower()
    if nome.endswith(".xlsx"):
        destino = ARQUIVO_BASE_VENDAS_PRIMEIRA_REVISAO_XLSX
    elif nome.endswith(".xls"):
        destino = ARQUIVO_BASE_VENDAS_PRIMEIRA_REVISAO_XLS
    elif nome.endswith(".csv"):
        destino = ARQUIVO_BASE_VENDAS_PRIMEIRA_REVISAO_CSV
    else:
        raise ValueError("Formato inválido. Use XLSX, XLS ou CSV.")

    # Evita manter duas bases antigas competindo entre si.
    for arquivo in ARQUIVOS_BASE_VENDAS_PRIMEIRA_REVISAO:
        if arquivo.exists() and arquivo != destino:
            arquivo.unlink()

    destino.write_bytes(uploaded_file.getvalue())
    return destino


def ler_arquivo_local_base_vendas(path):
    nome = str(path).lower()
    if nome.endswith(".xlsx") or nome.endswith(".xls"):
        return pd.read_excel(path, dtype=str)

    for sep in [";", ","]:
        for enc in ["utf-8-sig", "latin-1", "utf-8"]:
            try:
                df_local = pd.read_csv(path, sep=sep, encoding=enc, dtype=str)
                if df_local.shape[1] > 1:
                    return df_local
            except Exception:
                pass
    return pd.read_csv(path, dtype=str)


def inferir_marca_venda(row):
    texto = " ".join([
        str(row.get("MODELO_NA_MARCA_ORIGINAL", "")),
        str(row.get("MODELO_DESCRICAO", "")),
        str(row.get("FAMILIA_ORIGINAL", "")),
        str(row.get("EMPRESA_ORIGINAL", "")),
    ])
    texto = normalizar_texto(texto)

    marcas = ["FIAT", "JEEP", "RAM", "PEUGEOT", "CITROEN", "CITROËN"]
    for marca in marcas:
        if normalizar_texto(marca) in texto:
            return "CITROEN" if normalizar_texto(marca) == "CITROEN" else normalizar_texto(marca)

    # Quando vier no padrão JEEP/RENEGADE, usa a parte antes da barra.
    modelo_marca = str(row.get("MODELO_NA_MARCA_ORIGINAL", "")).strip()
    if "/" in modelo_marca:
        return modelo_marca.split("/")[0].strip().upper()

    return ""


def limpar_placa_venda(valor):
    texto = normalizar_texto(valor)
    texto = re.sub(r"[^A-Z0-9]", "", texto)
    return texto


def separar_telefones_venda(valor):
    texto = "" if pd.isna(valor) else str(valor)
    encontrados = re.findall(r"\(?\d{2}\)?\s*\d{4,5}[-\s]?\d{4}", texto)
    if not encontrados:
        digitos = normalizar_telefone_cruzamento(texto)
        encontrados = [digitos] if digitos else []

    telefones = []
    for tel in encontrados:
        tel_norm = normalizar_telefone_cruzamento(tel)
        if tel_norm and tel_norm not in telefones:
            telefones.append(tel_norm)

    celular = ""
    telefone = ""
    for tel in telefones:
        # No padrão BR com DDD, celular costuma ter 11 dígitos.
        if len(tel) >= 11 and not celular:
            celular = tel
        elif not telefone:
            telefone = tel

    if not celular and telefones:
        celular = telefones[0]
    if not telefone and len(telefones) > 1:
        telefone = telefones[1]

    return pd.Series({"CELULAR": celular, "TELEFONE": telefone})


@st.cache_data(show_spinner=False)
def carregar_base_vendas_primeira_revisao():
    """
    Lê a base mensal RVC013 / veículos vendidos e padroniza para alimentar a régua da 1ª revisão.

    Regra aplicada:
    - considera somente Grupo Movimento = VENDA, quando a coluna existir;
    - ignora DEVOLUÇÃO VENDA;
    - usa a coluna Data como DATA_VENDA, salvo se existir DATA VENDA/DT VENDA;
    - cruza principalmente por CHASSI/VIN.
    """
    arquivo = obter_arquivo_base_vendas_primeira_revisao()
    if arquivo is None:
        return pd.DataFrame()

    try:
        vendas = ler_arquivo_local_base_vendas(arquivo)
    except Exception:
        return pd.DataFrame()

    if vendas.empty:
        return pd.DataFrame()

    vendas.columns = vendas.columns.astype(str).str.strip()

    col_grupo_mov = encontrar_coluna(vendas, ["GRUPO MOVIMENTO", "MOVIMENTO", "TIPO MOVIMENTO"])
    col_data_venda = encontrar_coluna(
        vendas,
        ["DATA VENDA", "DT VENDA", "DATA DA VENDA", "DATA FATURAMENTO", "DATA EMISSAO", "DATA EMISSÃO", "DATA"],
        obrigatoria=False,
    )
    col_chassi = encontrar_coluna(vendas, CANDIDATOS_COLUNA_CHASSI, obrigatoria=False)

    if not col_data_venda or not col_chassi:
        return pd.DataFrame()

    col_placa = encontrar_coluna(vendas, ["PLACA"])
    col_ano = encontrar_coluna(vendas, ["ANO", "ANO MODELO", "MODELO ANO"])
    col_familia = encontrar_coluna(vendas, ["FAMILIA", "FAMÍLIA"])
    col_modelo = encontrar_coluna(vendas, ["MODELO"])
    col_modelo_marca = encontrar_coluna(vendas, ["MODELO NA MARCA", "MODELO MARCA", "GRUPO MODELO"])
    col_cliente = encontrar_coluna(vendas, ["CLIENTE", "NOME CLIENTE", "NOME DO CLIENTE"])
    col_cpf_cnpj = encontrar_coluna(vendas, ["CPF/CNPJ", "CPF CNPJ", "CPF", "CNPJ"])
    col_email = encontrar_coluna(vendas, ["EMAIL", "E-MAIL"])
    col_cidade = encontrar_coluna(vendas, ["CIDADE"])
    col_estado = encontrar_coluna(vendas, ["ESTADO", "UF"])
    col_fones = encontrar_coluna(vendas, ["FONE(S) / CONTATO", "FONES / CONTATO", "FONE", "TELEFONE", "CELULAR"])
    col_empresa = encontrar_coluna(vendas, ["EMPRESA", "EMPRESA COMPRA", "CONCESSIONARIA", "CONCESSIONÁRIA"])
    col_vendedor = encontrar_coluna(vendas, ["VENDEDOR"])
    col_valor_venda = encontrar_coluna(vendas, ["VALOR DA VENDA", "VALOR VENDA", "PREÇO PÚBLICO", "PRECO PUBLICO"])
    col_status_entrega = encontrar_coluna(vendas, ["STATUS ENTREGA"])

    base = vendas.copy()

    if col_grupo_mov:
        movimento = base[col_grupo_mov].fillna("").astype(str).apply(normalizar_texto)
        base = base[movimento == "VENDA"].copy()
    elif col_valor_venda:
        valor = converter_numero(base[col_valor_venda])
        base = base[valor > 0].copy()

    if base.empty:
        return pd.DataFrame()

    saida = pd.DataFrame()
    saida["CHASSI"] = base[col_chassi].fillna("").astype(str).str.strip().apply(normalizar_texto)
    saida["DATA_VENDA"] = converter_data(base[col_data_venda])
    saida["PLACA"] = base[col_placa].apply(limpar_placa_venda) if col_placa else ""
    saida["ANO_MODELO"] = extrair_ano_modelo(base[col_ano]) if col_ano else np.nan
    saida["MODELO_DESCRICAO"] = base[col_modelo_marca].fillna("").astype(str).str.strip() if col_modelo_marca else ""
    if col_modelo:
        saida["MODELO_DESCRICAO"] = saida["MODELO_DESCRICAO"].where(
            saida["MODELO_DESCRICAO"].astype(str).str.strip() != "",
            base[col_modelo].fillna("").astype(str).str.strip(),
        )
    if col_familia:
        saida["MODELO_DESCRICAO"] = saida["MODELO_DESCRICAO"].where(
            saida["MODELO_DESCRICAO"].astype(str).str.strip() != "",
            base[col_familia].fillna("").astype(str).str.strip(),
        )

    saida["MODELO_NA_MARCA_ORIGINAL"] = base[col_modelo_marca].fillna("").astype(str).str.strip() if col_modelo_marca else ""
    saida["FAMILIA_ORIGINAL"] = base[col_familia].fillna("").astype(str).str.strip() if col_familia else ""
    saida["EMPRESA_ORIGINAL"] = base[col_empresa].fillna("").astype(str).str.strip() if col_empresa else ""
    saida["VEICULO_MARCA"] = saida.apply(inferir_marca_venda, axis=1)

    saida["NOME_DO_CLIENTE"] = base[col_cliente].fillna("").astype(str).str.strip() if col_cliente else ""
    saida["CPF_CNPJ"] = base[col_cpf_cnpj].fillna("").astype(str).str.replace(r"\D", "", regex=True) if col_cpf_cnpj else ""
    saida["EMAIL"] = base[col_email].fillna("").astype(str).str.strip() if col_email else ""
    saida["CIDADE"] = base[col_cidade].fillna("").astype(str).str.strip() if col_cidade else ""
    saida["ESTADO"] = base[col_estado].fillna("").astype(str).str.strip() if col_estado else ""
    saida["NOME_CONCESSIONARIA"] = base[col_empresa].fillna("").astype(str).str.strip() if col_empresa else ""
    saida["VENDEDOR"] = base[col_vendedor].fillna("").astype(str).str.strip() if col_vendedor else ""
    saida["STATUS_ENTREGA_VENDA"] = base[col_status_entrega].fillna("").astype(str).str.strip() if col_status_entrega else ""

    if col_fones:
        telefones = base[col_fones].apply(separar_telefones_venda)
        saida["CELULAR"] = telefones["CELULAR"]
        saida["TELEFONE"] = telefones["TELEFONE"]
    else:
        saida["CELULAR"] = ""
        saida["TELEFONE"] = ""
    saida["FAX"] = ""

    saida = saida.replace({"nan": "", "None": "", "NaT": ""})
    saida = saida[(saida["CHASSI"] != "") & saida["DATA_VENDA"].notna()].copy()
    if saida.empty:
        return pd.DataFrame()

    saida = saida.sort_values(["CHASSI", "DATA_VENDA"])
    saida = saida.drop_duplicates(subset=["CHASSI"], keep="last")
    saida["ORIGEM_BASE_PROJECAO"] = "BASE DE VENDAS DO PERÍODO"
    return saida.reset_index(drop=True)


def contar_chassis_base_vendas_primeira_revisao():
    base = carregar_base_vendas_primeira_revisao()
    if base.empty or "CHASSI" not in base.columns:
        return 0
    return int(base["CHASSI"].nunique())


def enriquecer_base_oficina_com_base_vendas(df_oficina, base_vendas):
    """Preenche dados faltantes da base de oficina usando a base mensal de vendas por CHASSI."""
    if df_oficina is None or df_oficina.empty or base_vendas is None or base_vendas.empty:
        return df_oficina
    if "CHASSI" not in df_oficina.columns or "CHASSI" not in base_vendas.columns:
        return df_oficina

    cols_ref = [
        "CHASSI", "DATA_VENDA", "PLACA", "ANO_MODELO", "MODELO_DESCRICAO", "VEICULO_MARCA",
        "NOME_DO_CLIENTE", "CPF_CNPJ", "CELULAR", "TELEFONE", "FAX", "NOME_CONCESSIONARIA"
    ]
    cols_ref = [c for c in cols_ref if c in base_vendas.columns]
    ref = base_vendas[cols_ref].drop_duplicates(subset=["CHASSI"], keep="last").copy()
    ref = ref.rename(columns={c: f"{c}_VENDA_REF" for c in cols_ref if c != "CHASSI"})

    df_saida = df_oficina.merge(ref, on="CHASSI", how="left")

    for col in [c for c in cols_ref if c != "CHASSI"]:
        col_ref = f"{col}_VENDA_REF"
        if col_ref not in df_saida.columns:
            continue
        if col not in df_saida.columns:
            df_saida[col] = df_saida[col_ref]
        elif col == "DATA_VENDA":
            df_saida[col] = pd.to_datetime(df_saida[col], errors="coerce")
            df_saida[col_ref] = pd.to_datetime(df_saida[col_ref], errors="coerce")
            df_saida[col] = df_saida[col].where(df_saida[col].notna(), df_saida[col_ref])
        else:
            atual = df_saida[col].fillna("").astype(str).str.strip()
            ref_val = df_saida[col_ref].fillna("").astype(str).str.strip()
            df_saida[col] = df_saida[col].where(atual != "", ref_val)
        df_saida = df_saida.drop(columns=[col_ref])

    return df_saida


def montar_linhas_primeira_revisao_por_base_vendas(base_vendas, chassis_excluir=None):
    """
    Cria clientes de 1ª revisão a partir da base de vendas quando não há R1/revisão de entrega tabulada.
    """
    if base_vendas is None or base_vendas.empty:
        return pd.DataFrame()

    base = base_vendas.copy()
    base["CHASSI"] = base["CHASSI"].fillna("").astype(str).str.strip().apply(normalizar_texto)
    base = base[(base["CHASSI"] != "") & (pd.to_datetime(base["DATA_VENDA"], errors="coerce").notna())].copy()

    chassis_excluir = set(chassis_excluir or [])
    if chassis_excluir:
        base = base[~base["CHASSI"].isin(chassis_excluir)].copy()

    if base.empty:
        return pd.DataFrame()

    base["DATA_VENDA"] = pd.to_datetime(base["DATA_VENDA"], errors="coerce")
    base["DATA_BASE_PROJECAO"] = base["DATA_VENDA"]
    base["DATA_ULTIMA_REVISAO"] = pd.NaT
    base["KM_ULTIMA_REVISAO"] = np.nan
    base["KM"] = np.nan
    base["DATA_REFERENCIA"] = base["DATA_VENDA"]
    base["ORDEM_SERV"] = ""
    base["TIPO_OS"] = "BASE VENDAS"
    base["SERVICOS"] = "BASE DE VEÍCULOS VENDIDOS"
    base["DESCRICAO"] = "Cliente incluído pela data de venda para projeção da 1ª revisão."
    base["TEXTO_SERVICO"] = base["SERVICOS"] + " " + base["DESCRICAO"]
    base["EH_REVISAO"] = False
    base["EH_REVISAO_ENTREGA"] = False
    base["SEM_REVISAO_IDENTIFICADA"] = False
    base["BASE_PROJECAO_PRIMEIRA_REVISAO"] = True
    base["STATUS_HISTORICO_REVISAO"] = "PENDENTE REVISÃO"
    base["QTD_REVISOES_PERIODICAS"] = 0
    base["ULTIMA_REVISAO_PERIODICA_NUMERO"] = 0
    base["QUAL_REVISAO"] = 1
    base["ORIGEM_RELATORIO"] = "PROSPECÇÃO ATUAL"
    base["ORIGEM_BASE_PROJECAO"] = "BASE DE VENDAS DO PERÍODO"
    base["DATA_REVISAO_RELATORIO"] = pd.NaT

    for col in ["VEICULO_MARCA", "MODELO_DESCRICAO", "ANO_MODELO", "NOME_CONCESSIONARIA", "NOME_DO_CLIENTE", "CPF_CNPJ", "PLACA", "CELULAR", "TELEFONE", "FAX"]:
        if col not in base.columns:
            base[col] = ""

    base["MOTORIZACAO"] = base.apply(
        lambda r: inferir_motorizacao(r.get("VEICULO_MARCA", ""), r.get("MODELO_DESCRICAO", "")),
        axis=1,
    )
    regras = base.apply(
        lambda r: regra_km(r.get("VEICULO_MARCA", ""), r.get("MOTORIZACAO", "")),
        axis=1,
    )
    base = pd.concat([base, regras], axis=1)

    base["MEDIA_KM_DIA"] = np.nan
    base["KM_DESDE_ULTIMA_REVISAO_EST"] = np.nan
    base["DATA_MIN_TEMPO"] = base["DATA_BASE_PROJECAO"] + pd.DateOffset(months=11)
    base["DATA_MAX_TEMPO"] = base["DATA_BASE_PROJECAO"] + pd.DateOffset(months=12, days=29)
    base["DATA_ATUALIZAR_KM"] = base["DATA_BASE_PROJECAO"] + pd.DateOffset(months=6)
    base["DATA_LIMITE_REVALIDACAO_TEMPO"] = base["DATA_MAX_TEMPO"] + pd.DateOffset(months=5)
    base["DIAS_ATE_MIN_KM"] = np.nan
    base["DATA_MIN_KM"] = pd.NaT
    base["DATA_SUGERIDA_CONTATO"] = base["DATA_MIN_TEMPO"]
    base["ANO_PROX"] = base["DATA_SUGERIDA_CONTATO"].dt.year.astype("Int64").astype(str)
    base["MES_PROX"] = base["DATA_SUGERIDA_CONTATO"].dt.month
    base["STATUS_PROSPECCAO"] = base.apply(classificar_status, axis=1)
    base["TIPO_REVISAO"] = "POR DATA DE VENDA"

    return base


