def carregar_veiculos_vendidos():
    df_v = carregar_csv_padrao(
        ARQUIVO_VEICULOS_VENDIDOS,
        COLUNAS_VEICULOS_VENDIDOS,
        parse_dates=["DATA_IMPORTACAO", "DATA_RETORNO", "DATA_COMPRA_DADO", "DATA_STATUS_ACIONAMENTO", "DATA_PROXIMO_CONTATO"],
    )

    for col in ["QTD_CHASSIS_ENCONTRADOS", "QTD_TENTATIVAS"]:
        if col in df_v.columns:
            df_v[col] = pd.to_numeric(df_v[col], errors="coerce").fillna(0).astype(int)

    for col in ["STATUS_IDENTIFICACAO", "STATUS_NOVO_PROPRIETARIO", "STATUS_ACIONAMENTO", "REVERSAO_CONFIRMADA"]:
        if col in df_v.columns:
            df_v[col] = df_v[col].fillna("").astype(str)

    return df_v


def salvar_veiculos_vendidos(df_v):
    for col in COLUNAS_VEICULOS_VENDIDOS:
        if col not in df_v.columns:
            df_v[col] = ""
    df_v[COLUNAS_VEICULOS_VENDIDOS].to_csv(
        ARQUIVO_VEICULOS_VENDIDOS,
        index=False,
        sep=";",
        encoding="utf-8-sig",
    )


def normalizar_telefone_cruzamento(valor):
    """
    Limpa telefone para cruzamento.
    Remove símbolos e remove o 55 inicial quando vier como código do Brasil.
    """
    if pd.isna(valor):
        return ""
    digitos = re.sub(r"\D", "", str(valor))
    if digitos.startswith("55") and len(digitos) > 11:
        digitos = digitos[2:]
    return digitos


def gerar_chaves_telefone(valor):
    telefone = normalizar_telefone_cruzamento(valor)
    return {
        "COMPLETO": telefone,
        "ULTIMOS_8": telefone[-8:] if len(telefone) >= 8 else "",
        "ULTIMOS_6": telefone[-6:] if len(telefone) >= 6 else "",
    }


def etiqueta_indica_veiculo_vendido(etiquetas):
    texto = normalizar_texto(etiquetas)
    if not texto:
        return False

    padroes = [
        "NAO POSSUI O CARRO",
        "NAO POSSUI CARRO",
        "NAO POSSUI O VEICULO",
        "NAO POSSUI VEICULO",
        "NAO ESTA COM O CARRO",
        "NAO ESTA MAIS COM O CARRO",
        "VENDEU",
        "VENDIDO",
        "VENDA DO VEICULO",
    ]
    return any(p in texto for p in padroes)


def preparar_base_cruzamento_telefone(df_base):
    if df_base is None or df_base.empty:
        return pd.DataFrame()

    base = df_base.copy()

    for col in ["CHASSI", "PLACA", "NOME_DO_CLIENTE", "CPF_CNPJ", "CELULAR", "TELEFONE", "FAX", "VEICULO_MARCA", "MODELO_DESCRICAO"]:
        if col not in base.columns:
            base[col] = ""

    base["CHASSI"] = base["CHASSI"].fillna("").astype(str).str.strip()
    base = base[base["CHASSI"] != ""].copy()
    base = base.drop_duplicates(subset=["CHASSI"], keep="last").copy()

    def telefones_linha(row):
        telefones = []
        for col in ["CELULAR", "TELEFONE", "FAX"]:
            tel = normalizar_telefone_cruzamento(row.get(col, ""))
            if tel:
                telefones.append(tel)
        return list(dict.fromkeys(telefones))

    base["_TELEFONES_NORM"] = base.apply(telefones_linha, axis=1)
    base["_TEL_COMPLETO"] = base["_TELEFONES_NORM"].apply(lambda lista: set(lista))
    base["_TEL_8"] = base["_TELEFONES_NORM"].apply(lambda lista: set([t[-8:] for t in lista if len(t) >= 8]))
    base["_TEL_6"] = base["_TELEFONES_NORM"].apply(lambda lista: set([t[-6:] for t in lista if len(t) >= 6]))
    return base


def localizar_veiculo_por_telefone(df_base, telefone):
    base = preparar_base_cruzamento_telefone(df_base)
    chaves = gerar_chaves_telefone(telefone)

    resposta_vazia = {
        "STATUS_IDENTIFICACAO": "NÃO LOCALIZADO",
        "METODO_CRUZAMENTO": "",
        "QTD_CHASSIS_ENCONTRADOS": 0,
        "CHASSIS_ENCONTRADOS": "",
        "PLACAS_ENCONTRADAS": "",
        "MODELOS_ENCONTRADOS": "",
        "CHASSI_CONFIRMADO": "",
        "PLACA": "",
        "MARCA": "",
        "MODELO": "",
        "NOME_CLIENTE_ANTIGO": "",
        "CPF_CNPJ_ANTIGO": "",
        "CELULAR_ANTIGO": "",
        "TELEFONE_ANTIGO": "",
        "FAX_ANTIGO": "",
    }

    if base.empty:
        return resposta_vazia

    tentativas = [
        ("TELEFONE COMPLETO", "_TEL_COMPLETO", chaves["COMPLETO"]),
        ("ÚLTIMOS 8 DÍGITOS", "_TEL_8", chaves["ULTIMOS_8"]),
        ("ÚLTIMOS 6 DÍGITOS", "_TEL_6", chaves["ULTIMOS_6"]),
    ]

    for metodo, coluna_chave, chave in tentativas:
        if not chave:
            continue

        encontrados = base[base[coluna_chave].apply(lambda conjunto: chave in conjunto)].copy()
        if encontrados.empty:
            continue

        encontrados = encontrados.drop_duplicates(subset=["CHASSI"])
        qtd = encontrados["CHASSI"].nunique()

        chassis = " | ".join(encontrados["CHASSI"].fillna("").astype(str).head(20).tolist())
        placas = " | ".join(encontrados["PLACA"].fillna("").astype(str).drop_duplicates().head(20).tolist())
        modelos = " | ".join(encontrados["MODELO_DESCRICAO"].fillna("").astype(str).drop_duplicates().head(20).tolist())

        resposta = {
            "STATUS_IDENTIFICACAO": "CHASSI CONFIRMADO" if qtd == 1 else "VALIDAÇÃO MANUAL",
            "METODO_CRUZAMENTO": metodo,
            "QTD_CHASSIS_ENCONTRADOS": qtd,
            "CHASSIS_ENCONTRADOS": chassis,
            "PLACAS_ENCONTRADAS": placas,
            "MODELOS_ENCONTRADOS": modelos,
            "CHASSI_CONFIRMADO": "",
            "PLACA": "",
            "MARCA": "",
            "MODELO": "",
            "NOME_CLIENTE_ANTIGO": "",
            "CPF_CNPJ_ANTIGO": "",
            "CELULAR_ANTIGO": "",
            "TELEFONE_ANTIGO": "",
            "FAX_ANTIGO": "",
        }

        if qtd == 1:
            row = encontrados.iloc[0]
            resposta.update({
                "CHASSI_CONFIRMADO": row.get("CHASSI", ""),
                "PLACA": row.get("PLACA", ""),
                "MARCA": row.get("VEICULO_MARCA", ""),
                "MODELO": row.get("MODELO_DESCRICAO", ""),
                "NOME_CLIENTE_ANTIGO": row.get("NOME_DO_CLIENTE", ""),
                "CPF_CNPJ_ANTIGO": row.get("CPF_CNPJ", ""),
                "CELULAR_ANTIGO": row.get("CELULAR", ""),
                "TELEFONE_ANTIGO": row.get("TELEFONE", ""),
                "FAX_ANTIGO": row.get("FAX", ""),
            })

        return resposta

    return resposta_vazia


def importar_retorno_veiculos_vendidos(
    uploaded_file,
    df_base,
    data_retorno,
    nome_acao,
    progress_bar=None,
    status_placeholder=None,
):
    if status_placeholder is not None:
        status_placeholder.info("0% • Lendo a planilha importada...")

    if progress_bar is not None:
        progress_bar.progress(0)

    df_upload = ler_arquivo_importado(uploaded_file)
    df_upload.columns = df_upload.columns.astype(str).str.strip()

    if status_placeholder is not None:
        status_placeholder.info("10% • Conferindo colunas Telefone e Etiquetas...")

    if progress_bar is not None:
        progress_bar.progress(10)

    col_telefone = encontrar_coluna(df_upload, ["TELEFONE", "CELULAR", "WHATSAPP", "PHONE"], obrigatoria=True)
    col_etiquetas = encontrar_coluna(df_upload, ["ETIQUETAS", "ETIQUETA", "TAGS", "TAG", "STATUS"], obrigatoria=True)

    if status_placeholder is not None:
        status_placeholder.info("20% • Filtrando registros com etiqueta de veículo vendido...")

    if progress_bar is not None:
        progress_bar.progress(20)

    df_upload["_ETIQUETA_VENDIDO"] = df_upload[col_etiquetas].apply(etiqueta_indica_veiculo_vendido)
    df_upload = df_upload[df_upload["_ETIQUETA_VENDIDO"]].copy()

    if df_upload.empty:
        if progress_bar is not None:
            progress_bar.progress(100)
        if status_placeholder is not None:
            status_placeholder.warning("100% • Nenhum registro com etiqueta de veículo vendido foi encontrado.")
        return 0, {"confirmados": 0, "validacao": 0, "nao_localizados": 0}

    if status_placeholder is not None:
        status_placeholder.info("30% • Preparando base atual para cruzamento por telefone...")

    if progress_bar is not None:
        progress_bar.progress(30)

    vendidos = carregar_veiculos_vendidos()
    linhas = []
    total_linhas = len(df_upload)

    timestamp = pd.Timestamp.now().strftime("%Y%m%d%H%M%S")

    for i, row in df_upload.reset_index(drop=True).iterrows():
        telefone_original = row.get(col_telefone, "")
        etiquetas = row.get(col_etiquetas, "")
        localizacao = localizar_veiculo_por_telefone(df_base, telefone_original)

        linha = {
            "ID_VENDIDO": f"VEND_{timestamp}_{i+1:06d}",
            "DATA_IMPORTACAO": HOJE,
            "NOME_ACAO": nome_acao,
            "DATA_RETORNO": pd.to_datetime(data_retorno, errors="coerce"),
            "TELEFONE_RETORNO": telefone_original,
            "TELEFONE_LIMPO": normalizar_telefone_cruzamento(telefone_original),
            "ETIQUETAS": etiquetas,
            "STATUS_IDENTIFICACAO": localizacao["STATUS_IDENTIFICACAO"],
            "METODO_CRUZAMENTO": localizacao["METODO_CRUZAMENTO"],
            "QTD_CHASSIS_ENCONTRADOS": localizacao["QTD_CHASSIS_ENCONTRADOS"],
            "CHASSIS_ENCONTRADOS": localizacao["CHASSIS_ENCONTRADOS"],
            "PLACAS_ENCONTRADAS": localizacao["PLACAS_ENCONTRADAS"],
            "MODELOS_ENCONTRADOS": localizacao["MODELOS_ENCONTRADOS"],
            "CHASSI_CONFIRMADO": localizacao["CHASSI_CONFIRMADO"],
            "PLACA": localizacao["PLACA"],
            "MARCA": localizacao["MARCA"],
            "MODELO": localizacao["MODELO"],
            "NOME_CLIENTE_ANTIGO": localizacao["NOME_CLIENTE_ANTIGO"],
            "CPF_CNPJ_ANTIGO": localizacao["CPF_CNPJ_ANTIGO"],
            "CELULAR_ANTIGO": localizacao["CELULAR_ANTIGO"],
            "TELEFONE_ANTIGO": localizacao["TELEFONE_ANTIGO"],
            "FAX_ANTIGO": localizacao["FAX_ANTIGO"],
            "STATUS_NOVO_PROPRIETARIO": "NÃO LOCALIZADO",
            "DATA_COMPRA_DADO": pd.NaT,
            "NOME_NOVO_PROPRIETARIO": "",
            "CPF_CNPJ_NOVO": "",
            "CELULAR_NOVO": "",
            "TELEFONE_NOVO": "",
            "STATUS_ACIONAMENTO": "NÃO ACIONADO",
            "MOTIVO_PERDA": "",
            "DATA_STATUS_ACIONAMENTO": pd.NaT,
            "QTD_TENTATIVAS": 0,
            "DATA_PROXIMO_CONTATO": pd.NaT,
            "OBSERVACAO_ACIONAMENTO": "",
            "REVERSAO_CONFIRMADA": "NÃO",
            "OBSERVACAO_VALIDACAO": "",
        }
        linhas.append(linha)

        percentual = 30 + int(((i + 1) / total_linhas) * 55)
        percentual = min(percentual, 85)

        if progress_bar is not None:
            progress_bar.progress(percentual)

        if status_placeholder is not None:
            status_placeholder.info(
                f"{percentual}% • Cruzando telefone {i + 1:,} de {total_linhas:,}...".replace(",", ".")
            )

    if status_placeholder is not None:
        status_placeholder.info("90% • Gravando registros no arquivo veiculos_vendidos.csv...")

    if progress_bar is not None:
        progress_bar.progress(90)

    novo = pd.DataFrame(linhas)
    vendidos = pd.concat([vendidos, novo], ignore_index=True, sort=False)

    # Evita repetir o mesmo retorno da mesma ação quando a planilha for importada duas vezes.
    vendidos = vendidos.drop_duplicates(
        subset=["NOME_ACAO", "DATA_RETORNO", "TELEFONE_LIMPO", "ETIQUETAS"],
        keep="last",
    )

    salvar_veiculos_vendidos(vendidos)

    resumo = {
        "confirmados": int((novo["STATUS_IDENTIFICACAO"] == "CHASSI CONFIRMADO").sum()),
        "validacao": int((novo["STATUS_IDENTIFICACAO"] == "VALIDAÇÃO MANUAL").sum()),
        "nao_localizados": int((novo["STATUS_IDENTIFICACAO"] == "NÃO LOCALIZADO").sum()),
    }

    if progress_bar is not None:
        progress_bar.progress(100)

    if status_placeholder is not None:
        status_placeholder.success("100% • Importação concluída.")

    return len(novo), resumo

def confirmar_chassi_veiculo_vendido(id_vendido, chassi_confirmado, df_base, observacao=""):
    vendidos = carregar_veiculos_vendidos()
    if vendidos.empty:
        return False

    mask = vendidos["ID_VENDIDO"].astype(str) == str(id_vendido)
    if not mask.any():
        return False

    base = preparar_base_cruzamento_telefone(df_base)
    chassi_confirmado = str(chassi_confirmado).strip()
    encontrado = base[base["CHASSI"].astype(str).str.strip() == chassi_confirmado].copy()

    if encontrado.empty:
        raise ValueError("Chassi informado não foi localizado na base principal.")

    row = encontrado.iloc[0]

    vendidos.loc[mask, "STATUS_IDENTIFICACAO"] = "CHASSI CONFIRMADO"
    vendidos.loc[mask, "METODO_CRUZAMENTO"] = "VALIDAÇÃO MANUAL CONFIRMADA"
    vendidos.loc[mask, "CHASSI_CONFIRMADO"] = row.get("CHASSI", "")
    vendidos.loc[mask, "PLACA"] = row.get("PLACA", "")
    vendidos.loc[mask, "MARCA"] = row.get("VEICULO_MARCA", "")
    vendidos.loc[mask, "MODELO"] = row.get("MODELO_DESCRICAO", "")
    vendidos.loc[mask, "NOME_CLIENTE_ANTIGO"] = row.get("NOME_DO_CLIENTE", "")
    vendidos.loc[mask, "CPF_CNPJ_ANTIGO"] = row.get("CPF_CNPJ", "")
    vendidos.loc[mask, "CELULAR_ANTIGO"] = row.get("CELULAR", "")
    vendidos.loc[mask, "TELEFONE_ANTIGO"] = row.get("TELEFONE", "")
    vendidos.loc[mask, "FAX_ANTIGO"] = row.get("FAX", "")
    vendidos.loc[mask, "OBSERVACAO_VALIDACAO"] = observacao

    salvar_veiculos_vendidos(vendidos)
    return True


def importar_novos_proprietarios_vendidos(uploaded_file):
    df_upload = ler_arquivo_importado(uploaded_file)
    df_upload.columns = df_upload.columns.astype(str).str.strip()

    col_chassi = encontrar_coluna(df_upload, CANDIDATOS_COLUNA_CHASSI, obrigatoria=True)
    col_nome = encontrar_coluna(df_upload, ["NOME NOVO PROPRIETARIO", "NOME NOVO PROPRIETÁRIO", "NOVO PROPRIETARIO", "NOVO PROPRIETÁRIO", "NOME CLIENTE", "CLIENTE", "NOME"])
    col_cpf = encontrar_coluna(df_upload, ["CPF/CNPJ", "CPF CNPJ", "CPF", "CNPJ"])
    col_celular = encontrar_coluna(df_upload, ["CELULAR", "WHATSAPP"])
    col_telefone = encontrar_coluna(df_upload, ["TELEFONE", "FIXO", "PHONE"])

    vendidos = carregar_veiculos_vendidos()
    if vendidos.empty:
        return 0, 0

    atualizados = 0
    nao_encontrados = 0

    for _, row in df_upload.iterrows():
        chassi = str(row.get(col_chassi, "")).strip()
        if not chassi:
            continue

        mask = vendidos["CHASSI_CONFIRMADO"].fillna("").astype(str).str.strip() == chassi
        if not mask.any():
            nao_encontrados += 1
            continue

        vendidos.loc[mask, "STATUS_NOVO_PROPRIETARIO"] = "LOCALIZADO"
        vendidos.loc[mask, "DATA_COMPRA_DADO"] = HOJE
        if col_nome:
            vendidos.loc[mask, "NOME_NOVO_PROPRIETARIO"] = str(row.get(col_nome, "")).strip()
        if col_cpf:
            vendidos.loc[mask, "CPF_CNPJ_NOVO"] = str(row.get(col_cpf, "")).strip()
        if col_celular:
            vendidos.loc[mask, "CELULAR_NOVO"] = str(row.get(col_celular, "")).strip()
        if col_telefone:
            vendidos.loc[mask, "TELEFONE_NOVO"] = str(row.get(col_telefone, "")).strip()

        atualizados += int(mask.sum())

    salvar_veiculos_vendidos(vendidos)
    return atualizados, nao_encontrados


def atualizar_acionamento_veiculo_vendido(ids_vendidos, novo_status, motivo_perda="", observacao="", data_proximo_contato=None, reversao_confirmada=False):
    vendidos = carregar_veiculos_vendidos()
    if vendidos.empty:
        return 0

    ids_vendidos = set([str(x) for x in ids_vendidos])
    mask = vendidos["ID_VENDIDO"].astype(str).isin(ids_vendidos)

    if not mask.any():
        return 0

    if novo_status == "OPORTUNIDADE PERDIDA" and not motivo_perda:
        raise ValueError("Informe o motivo da perda.")

    if novo_status == "RECONTATO FUTURO" and not data_proximo_contato:
        raise ValueError("Informe a data do próximo contato.")

    if novo_status != "OPORTUNIDADE PERDIDA":
        motivo_perda = ""

    vendidos.loc[mask, "STATUS_ACIONAMENTO"] = novo_status
    vendidos.loc[mask, "MOTIVO_PERDA"] = motivo_perda
    vendidos.loc[mask, "DATA_STATUS_ACIONAMENTO"] = HOJE
    vendidos.loc[mask, "DATA_PROXIMO_CONTATO"] = pd.to_datetime(data_proximo_contato) if data_proximo_contato else pd.NaT
    vendidos.loc[mask, "OBSERVACAO_ACIONAMENTO"] = observacao
    vendidos.loc[mask, "QTD_TENTATIVAS"] = (
        pd.to_numeric(vendidos.loc[mask, "QTD_TENTATIVAS"], errors="coerce").fillna(0).astype(int) + 1
    )

    if reversao_confirmada or novo_status == "CONVERTIDO":
        vendidos.loc[mask, "REVERSAO_CONFIRMADA"] = "SIM"

    salvar_veiculos_vendidos(vendidos)
    return int(mask.sum())

# ======================================================
# PROCESSAMENTO DA BASE
# ======================================================
def mapear_colunas_base_oficina():
    cabecalho = pd.read_csv(
        ARQUIVO_BASE,
        sep=";",
        encoding="latin-1",
        nrows=0,
    )
    colunas_originais = list(cabecalho.columns)
    colunas_tratadas = [str(col).strip() for col in colunas_originais]
    original_por_tratada = {}
    for original, tratada in zip(colunas_originais, colunas_tratadas):
        original_por_tratada[tratada] = original

    df_cabecalho = pd.DataFrame(columns=colunas_tratadas)

    col_km = encontrar_coluna(df_cabecalho, ["KM", "QUILOMETRAGEM"], obrigatoria=True)
    col_chassi = encontrar_coluna(df_cabecalho, CANDIDATOS_COLUNA_CHASSI, obrigatoria=True)
    col_data_venda = encontrar_coluna(df_cabecalho, ["DATA VENDA", "DT VENDA"], obrigatoria=True)
    col_data_encer = encontrar_coluna(df_cabecalho, ["DATA ENCER.", "DATA ENCER", "DATA ENCERRAMENTO"])
    col_data_abert = encontrar_coluna(df_cabecalho, ["DATA ABERT.", "DATA ABERT", "DATA ABERTURA"])
    col_servicos = encontrar_coluna(df_cabecalho, ["SERVICOS", "SERVIÇOS", "SERVICO", "SERVIÇO"], obrigatoria=True)

    if not col_data_encer and not col_data_abert:
        raise KeyError("É necessário existir DATA ENCER. ou DATA ABERT. para ordenar as passagens.")

    renomear_tratado = {
        col_km: "KM",
        col_chassi: "CHASSI",
        col_data_venda: "DATA_VENDA",
        col_servicos: "SERVICOS",
    }
    opcionais = {
        col_data_encer: "DATA_ENCER",
        col_data_abert: "DATA_ABERT",
        encontrar_coluna(df_cabecalho, ["DESCRIÇÃO", "DESCRICAO"]): "DESCRICAO",
        encontrar_coluna(df_cabecalho, ["TIPO O.S.", "TIPO O.S", "TIPO OS", "TIPO O S"]): "TIPO_OS",
        encontrar_coluna(df_cabecalho, ["ORDEM SERV.", "ORDEM SERV", "ORDEM SERVICO", "ORDEM SERVIÇO", "OS"]): "ORDEM_SERV",
        encontrar_coluna(df_cabecalho, ["VEICULO MARCA", "VEÍCULO MARCA", "MARCA"]): "VEICULO_MARCA",
        encontrar_coluna(df_cabecalho, ["MODELO DESCRICAO", "MODELO DESCRIÇÃO", "MODELO"]): "MODELO_DESCRICAO",
        encontrar_coluna(df_cabecalho, ["ANO MODELO", "ANO MODELO VEICULO", "ANO MODELO VEÍCULO", "ANO MOD", "ANO_MOD", "MODELO ANO"]): "ANO_MODELO",
        encontrar_coluna(df_cabecalho, ["NOME CONCESSIONARIA", "NOME CONCESSIONÁRIA", "CONCESSIONARIA"]): "NOME_CONCESSIONARIA",
        encontrar_coluna(df_cabecalho, ["NOME DO CLIENTE", "NOME CLIENTE", "CLIENTE"]): "NOME_DO_CLIENTE",
        encontrar_coluna(df_cabecalho, ["CPF/CNPJ", "CPF CNPJ", "CPF", "CNPJ", "CPF/CNPJ CLIENTE", "CPF CNPJ CLIENTE"]): "CPF_CNPJ",
        encontrar_coluna(df_cabecalho, ["PLACA"]): "PLACA",
        encontrar_coluna(df_cabecalho, ["TELEFONE"]): "TELEFONE",
        encontrar_coluna(df_cabecalho, ["CELULAR"]): "CELULAR",
        encontrar_coluna(df_cabecalho, ["FAX"]): "FAX",
    }
    for original, novo in opcionais.items():
        if original:
            renomear_tratado[original] = novo

    usecols = [original_por_tratada[col] for col in renomear_tratado]
    return usecols, renomear_tratado


@st.cache_data(show_spinner="Carregando e processando a base...")
def processar_base():
    if not ARQUIVO_BASE.exists():
        raise FileNotFoundError(
            f"Arquivo {ARQUIVO_BASE.name} não encontrado na mesma pasta do app."
        )

    usecols, renomear = mapear_colunas_base_oficina()
    df = pd.read_csv(
        ARQUIVO_BASE,
        sep=";",
        encoding="latin-1",
        on_bad_lines="skip",
        low_memory=False,
        usecols=usecols,
    )
    df.columns = df.columns.str.strip()

    df = df.rename(columns=renomear)
    df["KM"] = converter_numero(df["KM"]).fillna(0)
    df["DATA_VENDA"] = converter_data(df["DATA_VENDA"])
    df["DATA_ENCER"] = converter_data(df["DATA_ENCER"]) if "DATA_ENCER" in df.columns else pd.NaT
    df["DATA_ABERT"] = converter_data(df["DATA_ABERT"]) if "DATA_ABERT" in df.columns else pd.NaT
    df["DATA_REFERENCIA"] = df["DATA_ENCER"].fillna(df["DATA_ABERT"])
    df["CHASSI"] = df["CHASSI"].astype(str).str.strip()
    df = df[df["CHASSI"].notna() & (df["CHASSI"] != "") & (df["CHASSI"].str.lower() != "nan")]

    if "DESCRICAO" not in df.columns:
        df["DESCRICAO"] = ""
    if "TIPO_OS" not in df.columns:
        df["TIPO_OS"] = ""
    if "VEICULO_MARCA" not in df.columns:
        df["VEICULO_MARCA"] = ""
    if "MODELO_DESCRICAO" not in df.columns:
        df["MODELO_DESCRICAO"] = ""
    if "ANO_MODELO" not in df.columns:
        df["ANO_MODELO"] = np.nan
    df["ANO_MODELO"] = extrair_ano_modelo(df["ANO_MODELO"])
    if "NOME_CONCESSIONARIA" not in df.columns:
        df["NOME_CONCESSIONARIA"] = ""
    if "NOME_DO_CLIENTE" not in df.columns:
        df["NOME_DO_CLIENTE"] = ""
    if "CPF_CNPJ" not in df.columns:
        df["CPF_CNPJ"] = ""
    if "PLACA" not in df.columns:
        df["PLACA"] = ""
    if "CELULAR" not in df.columns:
        df["CELULAR"] = ""
    if "TELEFONE" not in df.columns:
        df["TELEFONE"] = ""
    if "FAX" not in df.columns:
        df["FAX"] = ""

    # Complemento mensal: base de veículos vendidos para projetar 1ª revisão
    # quando não houver R1/revisão de entrega tabulada na passagem da oficina.
    base_vendas_primeira_revisao = carregar_base_vendas_primeira_revisao()
    if not base_vendas_primeira_revisao.empty:
        df = enriquecer_base_oficina_com_base_vendas(df, base_vendas_primeira_revisao)

    # Base de identificação da revisão:
    # usa coluna X/SERVIÇOS + coluna Y/DESCRIÇÃO, porque em muitos casos a revisão
    # aparece somente na descrição, enquanto SERVIÇOS vem como "SERVIÇOS GERAIS".
    df["SERVICOS_NORM"] = df["SERVICOS"].fillna("").astype(str).apply(normalizar_texto)
    df["DESCRICAO_NORM"] = df["DESCRICAO"].fillna("").astype(str).apply(normalizar_texto)
    df["TEXTO_SERVICO"] = df["SERVICOS"].fillna("").astype(str) + " " + df["DESCRICAO"].fillna("").astype(str)
    df["TEXTO_SERVICO_NORM"] = df["TEXTO_SERVICO"].apply(normalizar_texto)
    df["TIPO_OS_NORM"] = df["TIPO_OS"].apply(normalizar_texto)

    df["REVISAO_POR_SERVICOS_LINHA"] = (
        df["SERVICOS_NORM"].apply(identificar_revisao)
        | df.apply(lambda r: identificar_revisao_entrega(r["TIPO_OS_NORM"], r["SERVICOS_NORM"]), axis=1)
    )
    df["REVISAO_POR_DESCRICAO_LINHA"] = (
        df["DESCRICAO_NORM"].apply(identificar_revisao)
        | df.apply(lambda r: identificar_revisao_entrega(r["TIPO_OS_NORM"], r["DESCRICAO_NORM"]), axis=1)
    )
    df["EH_REVISAO_ENTREGA_LINHA"] = df.apply(
        lambda r: identificar_revisao_entrega(r["TIPO_OS_NORM"], r["TEXTO_SERVICO_NORM"]),
        axis=1,
    )
    df["EH_REVISAO_LINHA"] = (
        df["TEXTO_SERVICO_NORM"].apply(identificar_revisao)
        | df["EH_REVISAO_ENTREGA_LINHA"]
        | df["REVISAO_POR_SERVICOS_LINHA"]
        | df["REVISAO_POR_DESCRICAO_LINHA"]
    )

    grupo_passagem = ["CHASSI", "ORDEM_SERV"] if "ORDEM_SERV" in df.columns else ["CHASSI", "DATA_REFERENCIA", "KM"]

    colunas_base = [
        "CHASSI", "ORDEM_SERV", "TIPO_OS", "DATA_ABERT", "DATA_REFERENCIA", "DATA_VENDA", "KM",
        "VEICULO_MARCA", "MODELO_DESCRICAO", "ANO_MODELO", "NOME_CONCESSIONARIA", "NOME_DO_CLIENTE",
        "CPF_CNPJ", "PLACA", "TELEFONE", "CELULAR", "FAX"
    ]
    colunas_base = [c for c in colunas_base if c in df.columns]

    agg = {}
    for col in colunas_base:
        if col in grupo_passagem:
            continue
        if col in ["DATA_ABERT", "DATA_REFERENCIA"]:
            agg[col] = "max"
        elif col == "DATA_VENDA":
            agg[col] = "min"
        elif col == "KM":
            agg[col] = "max"
        else:
            agg[col] = ultimo_valido
    agg["EH_REVISAO_LINHA"] = "max"
    agg["EH_REVISAO_ENTREGA_LINHA"] = "max"
    agg["REVISAO_POR_SERVICOS_LINHA"] = "max"
    agg["REVISAO_POR_DESCRICAO_LINHA"] = "max"
    agg["SERVICOS"] = juntar_textos
    agg["DESCRICAO"] = juntar_textos
    agg["TEXTO_SERVICO"] = juntar_textos

    df_passagens = df.groupby(grupo_passagem, dropna=False, as_index=False).agg(agg)
    df_passagens = df_passagens.rename(columns={
        "EH_REVISAO_LINHA": "EH_REVISAO",
        "EH_REVISAO_ENTREGA_LINHA": "EH_REVISAO_ENTREGA",
        "REVISAO_POR_SERVICOS_LINHA": "REVISAO_POR_SERVICOS",
        "REVISAO_POR_DESCRICAO_LINHA": "REVISAO_POR_DESCRICAO",
    })
    df_passagens["TIPO_PASSAGEM"] = np.where(df_passagens["EH_REVISAO"], "REVISAO", "OUTROS_SERVICOS")
    df_passagens = df_passagens.sort_values(["CHASSI", "DATA_REFERENCIA", "KM"])

    ultimas_passagens = df_passagens.groupby("CHASSI", as_index=False).tail(1).copy()
    if "DATA_ABERT" in df_passagens.columns:
        ref_ultima_passagem = df_passagens[["CHASSI", "DATA_ABERT"]].copy()
        ref_ultima_passagem["DATA_ULTIMA_PASSAGEM"] = pd.to_datetime(ref_ultima_passagem["DATA_ABERT"], errors="coerce")
    else:
        ref_ultima_passagem = df_passagens[["CHASSI", "DATA_REFERENCIA"]].copy()
        ref_ultima_passagem["DATA_ULTIMA_PASSAGEM"] = pd.to_datetime(ref_ultima_passagem["DATA_REFERENCIA"], errors="coerce")
    ref_ultima_passagem = (
        ref_ultima_passagem[["CHASSI", "DATA_ULTIMA_PASSAGEM"]]
        .dropna(subset=["CHASSI"])
        .sort_values(["CHASSI", "DATA_ULTIMA_PASSAGEM"])
        .drop_duplicates("CHASSI", keep="last")
    )

    def anexar_data_ultima_passagem(resultado_base):
        if resultado_base is None or resultado_base.empty or "CHASSI" not in resultado_base.columns:
            return resultado_base
        resultado_base = resultado_base.drop(columns=["DATA_ULTIMA_PASSAGEM"], errors="ignore")
        return resultado_base.merge(ref_ultima_passagem, on="CHASSI", how="left")

    df_revisoes = df_passagens[df_passagens["EH_REVISAO"]].copy()

    # --------------------------------------------------
    # ABA 3 - Tempo médio de retorno (histórico de revisões realizadas)
    # Exclui revisão de entrega do contador analítico e usa DATA VENDA como base da revisão 1.
    # --------------------------------------------------
    eventos_analiticos = df_revisoes[~df_revisoes["EH_REVISAO_ENTREGA"].fillna(False)].copy()
    if not eventos_analiticos.empty:
        eventos_analiticos = eventos_analiticos.sort_values(["CHASSI", "DATA_REFERENCIA", "KM"])

        eventos_analiticos["MOTORIZACAO"] = eventos_analiticos.apply(
            lambda r: inferir_motorizacao(r.get("VEICULO_MARCA", ""), r.get("MODELO_DESCRICAO", "")),
            axis=1,
        )
        regras_eventos = eventos_analiticos.apply(
            lambda r: regra_km(r.get("VEICULO_MARCA", ""), r.get("MOTORIZACAO", "")),
            axis=1,
        )
        eventos_analiticos = pd.concat([eventos_analiticos, regras_eventos], axis=1)
        eventos_analiticos["KM_REVISAO_TEXTO"] = eventos_analiticos["TEXTO_SERVICO"].apply(extrair_km_revisao)

        eventos_analiticos["REVISAO_NUMERO_SEQUENCIAL"] = eventos_analiticos.groupby("CHASSI").cumcount() + 1
        eventos_analiticos["REVISAO_NUMERO_TEXTO"] = np.ceil(
            eventos_analiticos["KM_REVISAO_TEXTO"] / eventos_analiticos["KM_IDEAL"]
        )

        eventos_analiticos["REVISAO_NUMERO"] = (
            eventos_analiticos["REVISAO_NUMERO_TEXTO"]
            .where(eventos_analiticos["REVISAO_NUMERO_TEXTO"].notna(), eventos_analiticos["REVISAO_NUMERO_SEQUENCIAL"])
            .clip(lower=1)
            .astype(int)
        )

        # Se houver duplicidade de descrição ou lançamento da mesma revisão, mantém a última ocorrência daquele número.
        eventos_analiticos = eventos_analiticos.sort_values(["CHASSI", "DATA_REFERENCIA", "KM"])
        eventos_analiticos = eventos_analiticos.drop_duplicates(["CHASSI", "REVISAO_NUMERO"], keep="last")

        eventos_analiticos["DATA_REVISAO_ANTERIOR_ANALITICA"] = eventos_analiticos.groupby("CHASSI")["DATA_REFERENCIA"].shift(1)
        eventos_analiticos["BASE_DATA_ANALITICA"] = np.where(
            eventos_analiticos["REVISAO_NUMERO"] == 1,
            eventos_analiticos["DATA_VENDA"],
            eventos_analiticos["DATA_REVISAO_ANTERIOR_ANALITICA"],
        )
        eventos_analiticos["BASE_DATA_ANALITICA"] = pd.to_datetime(eventos_analiticos["BASE_DATA_ANALITICA"], errors="coerce")
        eventos_analiticos["DIAS_RETORNO"] = (
            eventos_analiticos["DATA_REFERENCIA"] - eventos_analiticos["BASE_DATA_ANALITICA"]
        ).dt.days
        eventos_analiticos.loc[eventos_analiticos["DIAS_RETORNO"] <= 0, "DIAS_RETORNO"] = np.nan
        eventos_analiticos["MESES_RETORNO"] = eventos_analiticos["DIAS_RETORNO"] / 30.44
        eventos_analiticos["FAIXA_RETORNO"] = eventos_analiticos["MESES_RETORNO"].apply(classificar_faixa_retorno)
        eventos_analiticos["PERFIL_RETORNO"] = eventos_analiticos["MESES_RETORNO"].apply(classificar_perfil_retorno)
        eventos_analiticos["TIPO_REVISAO_REALIZADA"] = eventos_analiticos.apply(classificar_tipo_revisao_realizada, axis=1)
        eventos_analiticos = eventos_analiticos.rename(columns={"DATA_REFERENCIA": "DATA_EXECUCAO_SERVICO"})
    else:
        eventos_analiticos = pd.DataFrame()

    # --------------------------------------------------
    # ABA 1 - Base atual de prospecção
    # --------------------------------------------------
    if df_revisoes.empty:
        resultado = ultimas_passagens.copy()
        resultado["SEM_REVISAO_IDENTIFICADA"] = True
        resultado["STATUS_PROSPECCAO"] = "OUTROS SERVIÇOS"
        resultado["STATUS_HISTORICO_REVISAO"] = "PENDENTE REVISÃO"
        resultado["TIPO_REVISAO"] = "OUTROS SERVIÇOS"
        resultado["DATA_SUGERIDA_CONTATO"] = resultado["DATA_REFERENCIA"] if "DATA_REFERENCIA" in resultado.columns else pd.NaT
        resultado["ANO_PROX"] = pd.to_datetime(resultado["DATA_SUGERIDA_CONTATO"], errors="coerce").dt.year.astype("Int64").astype(str)
        resultado["MES_PROX"] = pd.to_datetime(resultado["DATA_SUGERIDA_CONTATO"], errors="coerce").dt.month
        resultado["QUAL_REVISAO"] = np.nan
        resultado["ORIGEM_BASE_PROJECAO"] = "SEM REVISÃO IDENTIFICADA"

        linhas_vendas_primeira = montar_linhas_primeira_revisao_por_base_vendas(
            base_vendas_primeira_revisao,
            chassis_excluir=set(),
        )
        if not linhas_vendas_primeira.empty:
            chassis_vendas_primeira = set(linhas_vendas_primeira["CHASSI"].fillna("").astype(str))
            resultado = resultado[~resultado["CHASSI"].fillna("").astype(str).isin(chassis_vendas_primeira)].copy()
            resultado = pd.concat([resultado, linhas_vendas_primeira], ignore_index=True, sort=False)

        resultado = anexar_data_ultima_passagem(resultado)
        resultado = aplicar_status_agendado(resultado)
        resultado["MOTIVO_STATUS"] = resultado.apply(diagnosticar_motivo, axis=1)
        return resultado, eventos_analiticos

    df_revisoes["QTD_REVISOES"] = df_revisoes.groupby("CHASSI")["CHASSI"].transform("count")
    df_revisoes["DATA_REV_ANTERIOR"] = df_revisoes.groupby("CHASSI")["DATA_REFERENCIA"].shift(1)
    df_revisoes["KM_REV_ANTERIOR"] = df_revisoes.groupby("CHASSI")["KM"].shift(1)

    ultimas_revisoes = df_revisoes.groupby("CHASSI", as_index=False).tail(1).copy()
    ultimas_revisoes = ultimas_revisoes.rename(columns={
        "DATA_REFERENCIA": "DATA_ULTIMA_REVISAO",
        "KM": "KM_ULTIMA_REVISAO",
    })
    ultimas_revisoes["SEM_REVISAO_IDENTIFICADA"] = False
    ultimas_revisoes["BASE_PROJECAO_PRIMEIRA_REVISAO"] = (
        ultimas_revisoes["EH_REVISAO_ENTREGA"].fillna(False).astype(bool)
        & (ultimas_revisoes["QTD_REVISOES"] == 1)
    )

    tem_rev_anterior = ultimas_revisoes["DATA_REV_ANTERIOR"].notna()
    ultimas_revisoes["DIAS_BASE_MEDIA"] = np.where(
        tem_rev_anterior,
        (ultimas_revisoes["DATA_ULTIMA_REVISAO"] - ultimas_revisoes["DATA_REV_ANTERIOR"]).dt.days,
        (ultimas_revisoes["DATA_ULTIMA_REVISAO"] - ultimas_revisoes["DATA_VENDA"]).dt.days,
    )
    ultimas_revisoes["KM_BASE_MEDIA"] = np.where(
        tem_rev_anterior,
        ultimas_revisoes["KM_ULTIMA_REVISAO"] - ultimas_revisoes["KM_REV_ANTERIOR"],
        ultimas_revisoes["KM_ULTIMA_REVISAO"],
    )
    ultimas_revisoes.loc[ultimas_revisoes["DIAS_BASE_MEDIA"] <= 0, "DIAS_BASE_MEDIA"] = np.nan
    ultimas_revisoes.loc[ultimas_revisoes["KM_BASE_MEDIA"] <= 0, "KM_BASE_MEDIA"] = np.nan
    ultimas_revisoes["MEDIA_KM_DIA"] = ultimas_revisoes["KM_BASE_MEDIA"] / ultimas_revisoes["DIAS_BASE_MEDIA"]

    ultimas_revisoes["DATA_BASE_PROJECAO"] = np.where(
        ultimas_revisoes["BASE_PROJECAO_PRIMEIRA_REVISAO"] & ultimas_revisoes["DATA_VENDA"].notna(),
        ultimas_revisoes["DATA_VENDA"],
        ultimas_revisoes["DATA_ULTIMA_REVISAO"],
    )
    ultimas_revisoes["DATA_BASE_PROJECAO"] = pd.to_datetime(ultimas_revisoes["DATA_BASE_PROJECAO"], errors="coerce")
    ultimas_revisoes["ORIGEM_BASE_PROJECAO"] = np.where(
        ultimas_revisoes["BASE_PROJECAO_PRIMEIRA_REVISAO"],
        "R1 / REVISÃO DE ENTREGA",
        "HISTÓRICO DE PASSAGEM",
    )

    ultimas_revisoes["MOTORIZACAO"] = ultimas_revisoes.apply(
        lambda r: inferir_motorizacao(r.get("VEICULO_MARCA", ""), r.get("MODELO_DESCRICAO", "")),
        axis=1,
    )
    regras = ultimas_revisoes.apply(
        lambda r: regra_km(r.get("VEICULO_MARCA", ""), r.get("MOTORIZACAO", "")),
        axis=1,
    )
    ultimas_revisoes = pd.concat([ultimas_revisoes, regras], axis=1)

    dias_desde_base = (HOJE - ultimas_revisoes["DATA_BASE_PROJECAO"]).dt.days.clip(lower=0)
    ultimas_revisoes["KM_DESDE_ULTIMA_REVISAO_EST"] = ultimas_revisoes["MEDIA_KM_DIA"] * dias_desde_base
    ultimas_revisoes.loc[
        ultimas_revisoes["BASE_PROJECAO_PRIMEIRA_REVISAO"]
        & ultimas_revisoes["KM_DESDE_ULTIMA_REVISAO_EST"].isna(),
        "KM_DESDE_ULTIMA_REVISAO_EST",
    ] = 0

    ultimas_revisoes["DATA_MIN_TEMPO"] = ultimas_revisoes["DATA_BASE_PROJECAO"] + pd.DateOffset(months=11)
    ultimas_revisoes["DATA_MAX_TEMPO"] = ultimas_revisoes["DATA_BASE_PROJECAO"] + pd.DateOffset(months=12, days=29)
    ultimas_revisoes["DATA_ATUALIZAR_KM"] = ultimas_revisoes["DATA_BASE_PROJECAO"] + pd.DateOffset(months=6)
    ultimas_revisoes["DATA_LIMITE_REVALIDACAO_TEMPO"] = ultimas_revisoes["DATA_MAX_TEMPO"] + pd.DateOffset(months=5)

    ultimas_revisoes["DIAS_ATE_MIN_KM"] = ultimas_revisoes["KM_MIN"] / ultimas_revisoes["MEDIA_KM_DIA"]
    ultimas_revisoes["DATA_MIN_KM"] = ultimas_revisoes["DATA_BASE_PROJECAO"] + pd.to_timedelta(
        ultimas_revisoes["DIAS_ATE_MIN_KM"].round(), unit="D"
    )
    ultimas_revisoes["DATA_SUGERIDA_CONTATO"] = ultimas_revisoes[["DATA_MIN_KM", "DATA_MIN_TEMPO"]].min(axis=1)
    ultimas_revisoes["ANO_PROX"] = ultimas_revisoes["DATA_SUGERIDA_CONTATO"].dt.year.astype("Int64").astype(str)
    ultimas_revisoes["MES_PROX"] = ultimas_revisoes["DATA_SUGERIDA_CONTATO"].dt.month

    ultimas_revisoes["STATUS_PROSPECCAO"] = ultimas_revisoes.apply(classificar_status, axis=1)
    # Quantidade e número da última revisão periódica realizada.
    # Importante: R1 / revisão de entrega NÃO conta como revisão periódica realizada.
    # A coluna REVISÃO NÚMERO representa a PRÓXIMA revisão a prospectar.
    if not eventos_analiticos.empty:
        resumo_periodicas = (
            eventos_analiticos.groupby("CHASSI")
            .agg(
                QTD_REVISOES_PERIODICAS=("REVISAO_NUMERO", "count"),
                ULTIMA_REVISAO_PERIODICA_NUMERO=("REVISAO_NUMERO", "max"),
            )
            .reset_index()
        )
        ultimas_revisoes = ultimas_revisoes.merge(resumo_periodicas, on="CHASSI", how="left")
    else:
        ultimas_revisoes["QTD_REVISOES_PERIODICAS"] = 0
        ultimas_revisoes["ULTIMA_REVISAO_PERIODICA_NUMERO"] = 0

    ultimas_revisoes["QTD_REVISOES_PERIODICAS"] = (
        pd.to_numeric(ultimas_revisoes["QTD_REVISOES_PERIODICAS"], errors="coerce")
        .fillna(0)
        .astype(int)
    )
    ultimas_revisoes["ULTIMA_REVISAO_PERIODICA_NUMERO"] = (
        pd.to_numeric(ultimas_revisoes["ULTIMA_REVISAO_PERIODICA_NUMERO"], errors="coerce")
        .fillna(0)
        .astype(int)
    )

    ultimas_revisoes["STATUS_HISTORICO_REVISAO"] = np.where(
        ultimas_revisoes["QTD_REVISOES_PERIODICAS"] >= 1,
        "REVISADO",
        "PENDENTE REVISÃO",
    )

    ultimas_revisoes["QUAL_REVISAO"] = ultimas_revisoes["ULTIMA_REVISAO_PERIODICA_NUMERO"] + 1
    ultimas_revisoes["TIPO_REVISAO"] = ultimas_revisoes.apply(calcular_tipo_revisao, axis=1)

    chassis_com_revisao = set(ultimas_revisoes["CHASSI"])
    sem_revisao = ultimas_passagens[~ultimas_passagens["CHASSI"].isin(chassis_com_revisao)].copy()

    if not sem_revisao.empty:
        sem_revisao = sem_revisao.rename(columns={"DATA_REFERENCIA": "DATA_ULTIMA_PASSAGEM", "KM": "KM_ULTIMA_PASSAGEM"})
        sem_revisao["SEM_REVISAO_IDENTIFICADA"] = True
        sem_revisao["STATUS_PROSPECCAO"] = "OUTROS SERVIÇOS"
        sem_revisao["STATUS_HISTORICO_REVISAO"] = "PENDENTE REVISÃO"
        sem_revisao["TIPO_REVISAO"] = "OUTROS SERVIÇOS"
        sem_revisao["DATA_SUGERIDA_CONTATO"] = sem_revisao["DATA_ULTIMA_PASSAGEM"]
        sem_revisao["ANO_PROX"] = pd.to_datetime(sem_revisao["DATA_ULTIMA_PASSAGEM"], errors="coerce").dt.year.astype("Int64").astype(str)
        sem_revisao["MES_PROX"] = pd.to_datetime(sem_revisao["DATA_ULTIMA_PASSAGEM"], errors="coerce").dt.month
        sem_revisao["QUAL_REVISAO"] = np.nan
        sem_revisao["ORIGEM_BASE_PROJECAO"] = "SEM REVISÃO IDENTIFICADA"
        resultado = pd.concat([ultimas_revisoes, sem_revisao], ignore_index=True, sort=False)
    else:
        resultado = ultimas_revisoes.copy()

    linhas_vendas_primeira = montar_linhas_primeira_revisao_por_base_vendas(
        base_vendas_primeira_revisao,
        chassis_excluir=chassis_com_revisao,
    )
    if not linhas_vendas_primeira.empty:
        chassis_vendas_primeira = set(linhas_vendas_primeira["CHASSI"].fillna("").astype(str))
        # Se o mesmo chassi estava como OUTROS SERVIÇOS por falta de R1, substitui pela régua correta de 1ª revisão.
        resultado = resultado[~resultado["CHASSI"].fillna("").astype(str).isin(chassis_vendas_primeira)].copy()
        resultado = pd.concat([resultado, linhas_vendas_primeira], ignore_index=True, sort=False)

    # Linhas pendentes/prospecção atual.
    resultado["ORIGEM_RELATORIO"] = "PROSPECÇÃO ATUAL"
    resultado["DATA_REVISAO_RELATORIO"] = pd.NaT

    # Linhas de revisões já realizadas, para que a safra filtrada também mostre quem revisou.
    revisoes_realizadas_relatorio = montar_linhas_revisoes_realizadas_para_relatorio(eventos_analiticos)
    if not revisoes_realizadas_relatorio.empty:
        resultado = pd.concat([resultado, revisoes_realizadas_relatorio], ignore_index=True, sort=False)
        resultado = resultado.drop_duplicates(
            subset=["CHASSI", "QUAL_REVISAO", "STATUS_PROSPECCAO", "DATA_REVISAO_RELATORIO"],
            keep="last",
        )

    resultado = anexar_data_ultima_passagem(resultado)
    resultado = aplicar_status_agendado(resultado)
    resultado["MOTIVO_STATUS"] = resultado.apply(diagnosticar_motivo, axis=1)

    # Base da aba Retenção: todas as OS/passagens do período, não apenas revisões.
    # A coluna REVISAO_NUMERO é preenchida apenas quando a OS também for uma revisão,
    # permitindo manter o filtro de revisão sem excluir os demais tipos de OS por padrão.
    base_servicos_retencao = df_passagens.copy()
    if "DATA_REFERENCIA" in base_servicos_retencao.columns:
        base_servicos_retencao = base_servicos_retencao.rename(columns={"DATA_REFERENCIA": "DATA_EXECUCAO_SERVICO"})
    if "TIPO_OS" not in base_servicos_retencao.columns:
        base_servicos_retencao["TIPO_OS"] = ""
    base_servicos_retencao["TIPO_OS_ANALISE"] = (
        base_servicos_retencao["TIPO_OS"]
        .fillna("")
        .astype(str)
        .str.strip()
    )
    base_servicos_retencao.loc[
        base_servicos_retencao["TIPO_OS_ANALISE"].eq(""),
        "TIPO_OS_ANALISE",
    ] = "SEM TIPO OS"

    base_servicos_retencao["REVISAO_NUMERO"] = np.nan
    if not eventos_analiticos.empty:
        chaves_merge = ["CHASSI"]
        if "ORDEM_SERV" in base_servicos_retencao.columns and "ORDEM_SERV" in eventos_analiticos.columns:
            chaves_merge.append("ORDEM_SERV")
        elif "DATA_EXECUCAO_SERVICO" in base_servicos_retencao.columns and "DATA_EXECUCAO_SERVICO" in eventos_analiticos.columns:
            chaves_merge.append("DATA_EXECUCAO_SERVICO")
            if "KM" in base_servicos_retencao.columns and "KM" in eventos_analiticos.columns:
                chaves_merge.append("KM")

        colunas_merge = chaves_merge + ["REVISAO_NUMERO"]
        mapa_revisao = (
            eventos_analiticos[colunas_merge]
            .dropna(subset=["REVISAO_NUMERO"])
            .drop_duplicates(chaves_merge, keep="last")
        )
        base_servicos_retencao = base_servicos_retencao.drop(columns=["REVISAO_NUMERO"], errors="ignore").merge(
            mapa_revisao,
            on=chaves_merge,
            how="left",
        )
    base_servicos_retencao["QUAL_REVISAO"] = base_servicos_retencao["REVISAO_NUMERO"]

    return resultado, eventos_analiticos, base_servicos_retencao


# ======================================================
# CONTROLE MANUAL DA DATA DA BASE
# ======================================================
def carregar_data_ultima_atualizacao_base():
    """
    Carrega a data informada manualmente pela usuária como última atualização da base.
    Se o arquivo ainda não existir ou estiver inválido, usa a data de hoje como padrão.
    """
    if ARQUIVO_DATA_ATUALIZACAO_BASE.exists():
        try:
            texto_data = ARQUIVO_DATA_ATUALIZACAO_BASE.read_text(encoding="utf-8").strip()
            data_lida = pd.to_datetime(texto_data, errors="coerce")
            if pd.notna(data_lida):
                return data_lida.date()
        except Exception:
            pass
    return HOJE.date()


def salvar_data_ultima_atualizacao_base(data_base):
    data_base = pd.to_datetime(data_base, errors="coerce")
    if pd.isna(data_base):
        data_base = HOJE
    ARQUIVO_DATA_ATUALIZACAO_BASE.write_text(data_base.strftime("%Y-%m-%d"), encoding="utf-8")


